INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (3, 2, 'en', 'How Hex Works', '<p>Hexadecimal format represents each byte with two symbols from 00 to FF. It is convenient for binary inspection, protocol debugging, file analysis, byte-level operations, color values, and hashes.</p>', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (4, 2, 'ru', 'Как работает Hex', '<p>Hexadecimal-формат представляет каждый байт данных двумя символами от 00 до FF. Этот формат удобен для отображения бинарных данных, отладки протоколов, анализа файлов, работы с байтами, цветами и хешами.</p>', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (5, 3, 'en', 'How JWT Decoder Works', '<p>A JWT has three parts: Header, Payload, and Signature. This tool decodes Base64URL header and payload to inspect claims and metadata. Signature verification is not performed.</p>', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (6, 3, 'ru', 'Как работает JWT Decoder', '<p>JWT состоит из трёх частей: Header, Payload и Signature. Инструмент декодирует Base64URL-представление header и payload для анализа claims и метаданных. Проверка подписи не выполняется.</p>', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (7, 4, 'en', 'How URL Encoding Works', '<p>URL encoding replaces unsafe or reserved characters with percent-encoded values. For example, spaces become %20, and characters like ? or &amp; are converted into a safe format for URLs and HTTP requests.</p>', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (8, 4, 'ru', 'Как работает URL-кодирование', '<p>URL-кодирование заменяет небезопасные или зарезервированные символы на percent-коды. Например, пробелы становятся %20, а символы вроде ? или &amp; преобразуются в безопасный формат для URL и HTTP-запросов.</p>', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (22, 2, 'tr', 'Hex nasil calisir', '<p>Her bayt 00 ile FF arasinda iki hex semboluyle gosterilir.</p>', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (23, 2, 'pt', 'Como Hex funciona', '<p>Cada byte e representado por dois simbolos hex de 00 a FF.</p>', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (24, 2, 'it', 'Come funziona Hex', '<p>Ogni byte e rappresentato da due simboli hex da 00 a FF.</p>', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (25, 2, 'fr', 'Comment fonctionne Hex', '<p>Chaque byte est represente par deux caracteres hex de 00 a FF.</p>', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (26, 2, 'es', 'Como funciona Hex', '<p>Cada byte se representa con dos simbolos hex de 00 a FF.</p>', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (27, 2, 'de', 'Wie Hex funktioniert', '<p>Jedes Byte wird durch zwei Hex-Zeichen von 00 bis FF dargestellt.</p>', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (28, 3, 'tr', 'JWT Token Yapisi', '<p>JWT, nokta ile ayrilan uc bolumden olusur: Header, Payload ve Signature. Her bolum Base64URL ile kodlanir. Header algoritmay tanimlar, Payload claim\'leri ve kullanici verilerini icerir, Signature token butunlugunu dogrular.</p>', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (29, 3, 'pt', 'Estrutura do Token JWT', '<p>Um JWT possui tres partes separadas por pontos: Header, Payload e Signature. Cada parte e codificada em Base64URL. O header descreve o algoritmo, o payload contem claims e dados do usuario, e a signature verifica a integridade do token.</p>', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (30, 3, 'it', 'Struttura del Token JWT', '<p>Un JWT e composto da tre parti separate da punti: Header, Payload e Signature. Ogni parte e codificata in Base64URL. L\'header descrive l\'algoritmo, il payload contiene claim e dati utente, e la signature verifica l\'integrita del token.</p>', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (31, 3, 'fr', 'Structure d\'un Token JWT', '<p>Un JWT se compose de trois parties separees par des points : Header, Payload et Signature. Chaque partie est encodee en Base64URL. Le header decrit l\'algorithme, le payload contient les claims et donnees utilisateur, et la signature verifie l\'integrite du token.</p>', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (32, 3, 'es', 'Estructura del Token JWT', '<p>Un JWT tiene tres partes separadas por puntos: Header, Payload y Signature. Cada parte esta codificada en Base64URL. El header describe el algoritmo, el payload contiene claims y datos del usuario, y la signature verifica la integridad del token.</p>', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (33, 3, 'de', 'JWT-Token-Struktur', '<p>Ein JWT besteht aus drei durch Punkte getrennten Teilen: Header, Payload und Signature. Jeder Teil ist Base64URL-kodiert. Der Header beschreibt den Algorithmus, die Payload enthaelt Claims und Benutzerdaten, und die Signature prueft die Token-Integritaet.</p>', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (34, 4, 'tr', 'URL Kodlama Nasil Calisir', '<p>URL kodlama, guvensiz veya ayrilmis karakterleri yuzde tabanli kodlara donusturur. Ornegin bosluklar %20 olur; ? veya & gibi karakterler URL ve HTTP istekleri icin guvenli formata cevrilir.</p>', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (35, 4, 'pt', 'Como funciona a codificacao de URL', '<p>A codificacao de URL substitui caracteres inseguros ou reservados por valores percentuais. Por exemplo, espacos viram %20 e caracteres como ? ou & sao convertidos em formato seguro para URLs e requisicoes HTTP.</p>', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (36, 4, 'it', 'Come funziona la codifica URL', '<p>La codifica URL sostituisce caratteri non sicuri o riservati con valori percentuali. Ad esempio, gli spazi diventano %20 e caratteri come ? o & vengono convertiti in un formato sicuro per URL e richieste HTTP.</p>', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (37, 4, 'fr', 'Comment fonctionne l\'encodage URL', '<p>L\'encodage URL remplace les caracteres non surs ou reserves par des valeurs encodees avec un pourcentage. Par exemple, les espaces deviennent %20, et des caracteres comme ? ou & sont convertis dans un format sur pour les URLs et requetes HTTP.</p>', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (38, 4, 'es', 'Como funciona la codificacion URL', '<p>La codificacion URL reemplaza caracteres no seguros o reservados por valores con porcentaje. Por ejemplo, los espacios se convierten en %20 y caracteres como ? o & se transforman en un formato seguro para URLs y solicitudes HTTP.</p>', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (39, 4, 'de', 'So funktioniert URL-Kodierung', '<p>URL-Kodierung ersetzt unsichere oder reservierte Zeichen durch Prozentwerte. Zum Beispiel werden Leerzeichen zu %20, und Zeichen wie ? oder & werden in ein sicheres Format fuer URLs und HTTP-Anfragen umgewandelt.</p>', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (49, 9, 'en', 'Hex and Security', '<p>Hex is a byte representation format, not an encryption method. A hex string can be converted back to original data without a password or secret key. This format helps display and transfer binary data as text, but it does not provide protection or confidentiality.</p>', '2026-05-17 11:49:37', '2026-05-17 11:49:37');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (50, 9, 'ru', 'Hex и безопасность', '<p>Hex — это способ представления байтов, а не метод шифрования. Hex-строку можно легко преобразовать обратно в исходные данные без пароля или секретного ключа. Этот формат помогает читать и передавать бинарные данные в текстовом виде, но не обеспечивает защиту или конфиденциальность информации.</p>', '2026-05-17 11:49:37', '2026-05-17 11:49:37');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (51, 11, 'en', 'URL Encoding and Security', '<p>All encoding and decoding happens locally in your browser. Your text is never uploaded or processed on external servers.</p>', '2026-05-17 11:49:37', '2026-05-17 11:49:37');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (52, 11, 'ru', 'URL-кодирование и безопасность', '<p>Все кодирование и декодирование выполняется локально в вашем браузере. Ваш текст не загружается и не обрабатывается на внешних серверах.</p>', '2026-05-17 11:49:37', '2026-05-17 11:49:37');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (60, 9, 'tr', 'Hex ve guvenlik', '<p>Hex bir bayt gosterim bicimidir, sifreleme degildir.</p>', '2026-05-17 11:53:15', '2026-05-17 11:53:15');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (61, 9, 'pt', 'Hex e seguranca', '<p>Hex e um formato de representacao de bytes, nao um metodo de criptografia.</p>', '2026-05-17 11:53:15', '2026-05-17 11:53:15');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (62, 9, 'it', 'Hex e sicurezza', '<p>Hex e un formato di rappresentazione dei byte, non una crittografia.</p>', '2026-05-17 11:53:15', '2026-05-17 11:53:15');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (63, 9, 'fr', 'Hex et securite', '<p>Hex est un format de representation des bytes, pas un chiffrement.</p>', '2026-05-17 11:53:15', '2026-05-17 11:53:15');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (64, 9, 'es', 'Hex y seguridad', '<p>Hex es un formato de representacion de bytes, no un metodo de cifrado. Se puede revertir sin clave secreta.</p>', '2026-05-17 11:53:15', '2026-05-17 11:53:15');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (65, 9, 'de', 'Hex und Sicherheit', '<p>Hex ist ein Darstellungsformat fuer Bytes, keine Verschluesselung.</p>', '2026-05-17 11:53:15', '2026-05-17 11:53:15');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (66, 10, 'tr', 'Yerel JWT Islemi', '<p>Tum JWT cozumleme islemleri tarayicinizda yerel olarak yapilir. Tokenlariniz hicbir zaman harici sunuculara gonderilmez, saklanmaz veya paylasilmaz. Bu arac yalnizca JWT yapisini analiz etmek icin tasarlanmistir — header, payload ve claim\'leri inceleme amaclidir. Imza dogrulamasi yapilmaz.</p>', '2026-05-17 11:53:15', '2026-05-17 11:53:15');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (67, 10, 'pt', 'Processamento local de JWT', '<p>Toda decodificacao JWT e realizada localmente no navegador. Os tokens nunca sao enviados, armazenados ou compartilhados com servidores externos. Esta ferramenta e projetada para analisar a estrutura JWT — inspecionar header, payload e claims. A verificacao de assinatura nao e realizada.</p>', '2026-05-17 11:53:15', '2026-05-17 11:53:15');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (68, 10, 'it', 'Elaborazione locale di JWT', '<p>Tutta la decodifica JWT avviene localmente nel browser. I token non vengono mai inviati, salvati o condivisi con server esterni. Questo strumento e progettato per analizzare la struttura JWT — ispezionare header, payload e claim. La verifica della firma non viene eseguita.</p>', '2026-05-17 11:53:15', '2026-05-17 11:53:15');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (69, 10, 'fr', 'Traitement local des JWT', '<p>Tout le decodage JWT s\'effectue localement dans votre navigateur. Les tokens ne sont jamais envoyes, stockes ou partages avec des serveurs externes. Cet outil est destine uniquement a l\'analyse de la structure JWT — inspection du header, payload et claims. La verification de signature n\'est pas effectuee.</p>', '2026-05-17 11:53:15', '2026-05-17 11:53:15');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (70, 10, 'es', 'Procesamiento local de JWT', '<p>Toda la decodificacion JWT se realiza localmente en tu navegador. Los tokens nunca son enviados, almacenados ni compartidos con servidores externos. Esta herramienta esta disenada para analizar la estructura JWT — inspeccionar header, payload y claims. No se realiza verificacion de firma.</p>', '2026-05-17 11:53:15', '2026-05-17 11:53:15');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (71, 10, 'de', 'Lokale JWT-Verarbeitung', '<p>Die gesamte JWT-Dekodierung erfolgt lokal in Ihrem Browser. Tokens werden niemals an externe Server gesendet, gespeichert oder weitergegeben. Dieses Tool dient ausschliesslich der Analyse der JWT-Struktur — zur Inspektion von Header, Payload und Claims. Eine Signaturverifizierung wird nicht durchgefuehrt.</p>', '2026-05-17 11:53:15', '2026-05-17 11:53:15');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (72, 11, 'tr', 'URL Kodlama ve Guvenlik', '<p>Tum kodlama ve cozme islemleri tarayicinizda yerel olarak yapilir. Metniniz harici sunuculara yuklenmez veya orada islenmez.</p>', '2026-05-17 11:53:15', '2026-05-17 11:53:15');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (73, 11, 'pt', 'Codificacao de URL e seguranca', '<p>Toda a codificacao e decodificacao acontece localmente no navegador. Seu texto nao e enviado nem processado em servidores externos.</p>', '2026-05-17 11:53:15', '2026-05-17 11:53:15');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (74, 11, 'it', 'Codifica URL e sicurezza', '<p>Tutta la codifica e decodifica avviene localmente nel browser. Il testo non viene caricato o elaborato su server esterni.</p>', '2026-05-17 11:53:15', '2026-05-17 11:53:15');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (75, 11, 'fr', 'Encodage URL et securite', '<p>Tout l\'encodage et le decodage se fait localement dans votre navigateur. Votre texte n\'est ni envoye ni traite sur des serveurs externes.</p>', '2026-05-17 11:53:15', '2026-05-17 11:53:15');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (76, 11, 'es', 'Codificacion URL y seguridad', '<p>Toda la codificacion y decodificacion se realiza localmente en tu navegador. Tu texto no se sube ni se procesa en servidores externos.</p>', '2026-05-17 11:53:15', '2026-05-17 11:53:15');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (77, 11, 'de', 'URL-Kodierung und Sicherheit', '<p>Die gesamte Kodierung und Dekodierung erfolgt lokal im Browser. Ihr Text wird nicht hochgeladen und nicht auf externen Servern verarbeitet.</p>', '2026-05-17 11:53:15', '2026-05-17 11:53:15');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (181, 27, 'en', 'How Binary Conversion Works', '<p>Each byte is represented by 8 bits made of 0 and 1. Text is first converted to bytes (UTF-8), then each byte is shown as an 8-bit binary group. Decoding performs the reverse operation.</p>', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (182, 27, 'es', 'Como funciona la conversion Binary', '<p>Cada byte se representa con 8 bits de 0 y 1. El texto primero se convierte a bytes (UTF-8), y luego cada byte se muestra como un grupo binary de 8 bits. La decodificacion realiza la operacion inversa.</p>', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (183, 27, 'pt', 'Como funciona a conversao Binary', '<p>Cada byte e representado por 8 bits de 0 e 1. O texto primeiro e convertido em bytes (UTF-8), depois cada byte e exibido como um grupo binary de 8 bits. A decodificacao realiza a operacao inversa.</p>', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (184, 27, 'ru', 'Как работает Binary преобразование', '<p>Каждый байт представляется 8 битами из 0 и 1. Сначала текст переводится в байты (UTF-8), затем каждый байт показывается как 8-битная binary-группа. Декодирование выполняет обратную операцию.</p>', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (185, 27, 'tr', 'Binary donusumu nasil calisir', '<p>Her bayt 0 ve 1\'lerden olusan 8 bit ile gosterilir. Metin once baytlara (UTF-8) donusturulur, sonra her bayt 8 bitlik binary grup olarak gosterilir. Cozumleme ters islemi uygular.</p>', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (186, 27, 'fr', 'Comment fonctionne la conversion Binary', '<p>Chaque octet est represente par 8 bits composes de 0 et 1. Le texte est d\'abord converti en octets (UTF-8), puis chaque octet est affiche comme un groupe binary de 8 bits. Le decodage effectue l\'operation inverse.</p>', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (187, 27, 'de', 'So funktioniert die Binary-Konvertierung', '<p>Jedes Byte wird durch 8 Bits aus 0 und 1 dargestellt. Text wird zuerst in Bytes (UTF-8) umgewandelt, dann wird jedes Byte als 8-Bit-Binary-Gruppe angezeigt. Die Dekodierung fuhrt den umgekehrten Vorgang aus.</p>', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (188, 27, 'it', 'Come funziona la conversione Binary', '<p>Ogni byte e rappresentato da 8 bit composti da 0 e 1. Il testo viene prima convertito in byte (UTF-8), poi ogni byte viene mostrato come gruppo binary da 8 bit. La decodifica esegue l\'operazione inversa.</p>', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (189, 28, 'en', 'Binary and Security', '<p>Binary conversion is a representation format, not encryption. Binary data can be restored back to text without a password. Use cryptographic tools when confidentiality is required.</p>', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (190, 28, 'es', 'Binary y seguridad', '<p>La conversion binary es un formato de representacion, no un metodo de cifrado. Los datos binary pueden recuperarse a texto sin contrasena. Para confidencialidad, usa herramientas criptograficas.</p>', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (191, 28, 'pt', 'Binary e seguranca', '<p>A conversao binary e um formato de representacao, nao um metodo de criptografia. Dados binary podem ser restaurados para texto sem senha. Para confidencialidade, use ferramentas criptograficas.</p>', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (192, 28, 'ru', 'Binary и безопасность', '<p>Binary-преобразование — это формат представления данных, а не шифрование. Binary-данные можно восстановить в текст без пароля. Для конфиденциальности используйте криптографические инструменты.</p>', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (193, 28, 'tr', 'Binary ve guvenlik', '<p>Binary donusumu bir gosterim bicimidir, sifreleme yontemi degildir. Binary veri parolasiz sekilde tekrar metne donusturulebilir. Gizlilik icin kriptografik araclar kullanin.</p>', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (194, 28, 'fr', 'Binary et securite', '<p>La conversion binary est un format de representation, pas une methode de chiffrement. Les donnees binary peuvent etre reconverties en texte sans mot de passe. Pour la confidentialite, utilisez des outils cryptographiques.</p>', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (195, 28, 'de', 'Binary und Sicherheit', '<p>Binary-Konvertierung ist ein Darstellungsformat, keine Verschlusselung. Binary-Daten konnen ohne Passwort wieder in Text zuruckgewandelt werden. Fur Vertraulichkeit sollten kryptographische Werkzeuge verwendet werden.</p>', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (196, 28, 'it', 'Binary e sicurezza', '<p>La conversione binary e un formato di rappresentazione, non un metodo di crittografia. I dati binary possono essere riconvertiti in testo senza password. Per la riservatezza usa strumenti crittografici.</p>', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (197, 29, 'en', 'How Base64 Works', '<p>Base64 converts binary data into a text string of ASCII characters. Every 3 bytes of source data are encoded into 4 Base64 characters, which makes the output about one third longer. This format is commonly used in APIs, JSON, email, HTTP headers, and other text protocols.</p>', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (198, 29, 'es', 'Cómo funciona Base64', '<p>Base64 convierte datos binarios en una cadena de texto de caracteres ASCII. Cada 3 bytes de los datos de origen se codifican en 4 caracteres Base64, por lo que el resultado es aproximadamente un tercio más largo. Este formato es conveniente para APIs, JSON, email, encabezados HTTP y otros protocolos de texto.</p>', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (199, 29, 'pt', 'Como o Base64 funciona', '<p>Base64 converte dados binários em uma string de caracteres ASCII. Cada 3 bytes dos dados de origem são codificados em 4 caracteres Base64, tornando o resultado cerca de um terço mais longo. Este formato é conveniente para APIs, JSON, email, cabeçalhos HTTP e outros protocolos de texto.</p>', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (200, 29, 'ru', 'Как работает Base64', '<p>Base64 преобразует бинарные данные в текстовую строку из ASCII-символов. Каждые 3 байта исходных данных кодируются в 4 символа Base64, поэтому результат обычно становится длиннее примерно на треть. Такой формат удобно использовать в API, JSON, email, HTTP-заголовках и других текстовых протоколах.</p>', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (201, 29, 'tr', 'Base64 Nasıl Çalışır', '<p>Base64, ikili verileri ASCII karakterlerinden oluşan bir metin dizisine dönüştürür. Her 3 kaynak bayt, 4 Base64 karakterine kodlanır ve bu nedenle sonuç yaklaşık üçte bir daha uzun olur. Bu format API, JSON, e-posta, HTTP başlıkları ve diğer metin tabanlı protokollerde kullanışlıdır.</p>', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (202, 29, 'fr', 'Comment fonctionne Base64', '<p>Base64 convertit des données binaires en une chaîne de caractères ASCII. Chaque 3 octets de données source sont encodés en 4 caractères Base64, ce qui rend le résultat environ un tiers plus long. Ce format est pratique pour les API, JSON, e-mail, les en-têtes HTTP et autres protocoles texte.</p>', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (203, 29, 'de', 'Wie Base64 funktioniert', '<p>Base64 konvertiert Binärdaten in eine Textzeichenkette aus ASCII-Zeichen. Jeweils 3 Bytes der Quelldaten werden in 4 Base64-Zeichen kodiert, sodass das Ergebnis etwa ein Drittel länger wird. Dieses Format eignet sich für APIs, JSON, E-Mail, HTTP-Header und andere textbasierte Protokolle.</p>', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (204, 29, 'it', 'Come funziona Base64', '<p>Base64 converte i dati binari in una stringa di caratteri ASCII. Ogni 3 byte dei dati sorgente vengono codificati in 4 caratteri Base64, rendendo il risultato circa un terzo più lungo. Questo formato è pratico per API, JSON, email, header HTTP e altri protocolli testuali.</p>', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (205, 30, 'en', 'Base64 and Security', '<p>Base64 is a way to represent data, not an encryption method. An encoded string can be easily decoded back without a password or secret key. Base64 is useful for transferring data, but it does not provide protection or confidentiality.</p>', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (206, 30, 'es', 'Base64 y seguridad', '<p>Base64 es una forma de representar datos, no un método de cifrado. Una cadena codificada se puede decodificar fácilmente sin contraseña ni clave secreta. Base64 es útil para transmitir datos, pero no ofrece protección ni confidencialidad.</p>', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (207, 30, 'pt', 'Base64 e segurança', '<p>Base64 é uma forma de representar dados, não um método de criptografia. Uma string codificada pode ser facilmente decodificada sem senha ou chave secreta. Base64 é útil para transmitir dados, mas não oferece proteção nem confidencialidade.</p>', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (208, 30, 'ru', 'Base64 и безопасность', '<p>Base64 — это способ представления данных, а не метод шифрования. Закодированную строку можно легко декодировать обратно без пароля или секретного ключа. Base64 удобно использовать для передачи данных, но он не обеспечивает защиту или конфиденциальность информации.</p>', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (209, 30, 'tr', 'Base64 ve güvenlik', '<p>Base64, veriyi temsil etmenin bir yoludur; bir şifreleme yöntemi değildir. Kodlanmış bir metin parola veya gizli anahtar olmadan kolayca geri çözülebilir. Base64 veri aktarımı için kullanışlıdır, ancak koruma veya gizlilik sağlamaz.</p>', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (210, 30, 'fr', 'Base64 et sécurité', '<p>Base64 est une façon de représenter des données, pas une méthode de chiffrement. Une chaîne encodée peut être facilement décodée sans mot de passe ni clé secrète. Base64 est utile pour transmettre des données, mais ne garantit ni protection ni confidentialité.</p>', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (211, 30, 'de', 'Base64 und Sicherheit', '<p>Base64 ist eine Art, Daten darzustellen, kein Verschlüsselungsverfahren. Eine codierte Zeichenkette kann ohne Passwort oder geheimen Schlüssel leicht wieder decodiert werden. Base64 eignet sich für die Datenübertragung, bietet aber keinen Schutz und keine Vertraulichkeit.</p>', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (212, 30, 'it', 'Base64 e sicurezza', '<p>Base64 è un modo per rappresentare i dati, non un metodo di crittografia. Una stringa codificata può essere decodificata facilmente senza password o chiave segreta. Base64 è utile per trasmettere dati, ma non offre protezione né riservatezza.</p>', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (213, 31, 'en', 'How ASCII Conversion Works', '<p>Each supported character has a numeric ASCII value. For example, uppercase A is 65, lowercase a is 97, and a space is 32. The converter reads each character and replaces it with its corresponding code, or performs the reverse operation when decoding.</p>', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (214, 31, 'es', 'Como funciona la conversion ASCII', '<p>Cada caracter compatible tiene un valor ASCII numerico. Por ejemplo, A mayuscula es 65, a minuscula es 97 y el espacio es 32. El convertidor reemplaza cada caracter por su codigo o hace la operacion inversa al decodificar.</p>', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (215, 31, 'pt', 'Como funciona a conversao ASCII', '<p>Cada caractere suportado tem um valor ASCII numerico. Por exemplo, A maiusculo e 65, a minusculo e 97 e espaco e 32. O conversor substitui cada caractere pelo codigo correspondente ou faz o processo inverso ao decodificar.</p>', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (216, 31, 'ru', 'Как работает ASCII-конвертация', '<p>Каждый поддерживаемый символ имеет числовое ASCII-значение. Например, заглавная A — это 65, строчная a — 97, а пробел — 32. Конвертер заменяет символы их кодами или выполняет обратное преобразование при декодировании.</p>', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (217, 31, 'tr', 'ASCII Donusumu Nasil Calisir', '<p>Desteklenen her karakterin sayisal bir ASCII degeri vardir. Ornegin buyuk A 65, kucuk a 97 ve bosluk 32\'dir. Donusturucu her karakteri karsilik gelen kodla degistirir veya cozumlemede ters islemi yapar.</p>', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (218, 31, 'fr', 'Comment fonctionne la conversion ASCII', '<p>Chaque caractere pris en charge possede une valeur ASCII numerique. Par exemple, A majuscule vaut 65, a minuscule vaut 97 et l espace vaut 32. Le convertisseur remplace chaque caractere par son code, ou fait l operation inverse en decode.</p>', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (219, 31, 'de', 'So funktioniert ASCII-Konvertierung', '<p>Jedes unterstuetzte Zeichen hat einen numerischen ASCII-Wert. Zum Beispiel ist grosses A gleich 65, kleines a gleich 97 und Leerzeichen gleich 32. Der Konverter ersetzt Zeichen durch Codes oder macht beim Dekodieren den umgekehrten Schritt.</p>', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (220, 31, 'it', 'Come funziona la conversione ASCII', '<p>Ogni carattere supportato ha un valore ASCII numerico. Per esempio, A maiuscola e 65, a minuscola e 97 e lo spazio e 32. Il convertitore sostituisce i caratteri con il codice corrispondente o esegue l operazione inversa in decodifica.</p>', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (221, 32, 'en', 'Security & Weakness', '<p>Your input is processed locally in your browser. ASCII conversion is not encryption and should not be used to protect sensitive information.</p>', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (222, 32, 'es', 'Seguridad y debilidades', '<p>Tu entrada se procesa localmente en el navegador. La conversion ASCII no es cifrado y no debe usarse para proteger informacion sensible.</p>', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (223, 32, 'pt', 'Seguranca e fraquezas', '<p>Sua entrada e processada localmente no navegador. Conversao ASCII nao e criptografia e nao deve ser usada para proteger dados sensiveis.</p>', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (224, 32, 'ru', 'Безопасность и слабые стороны', '<p>Ввод обрабатывается локально в вашем браузере. ASCII-конвертация не является шифрованием и не должна использоваться для защиты чувствительных данных.</p>', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (225, 32, 'tr', 'Guvenlik ve zayifliklar', '<p>Girdiniz tarayicida yerel olarak islenir. ASCII donusumu sifreleme degildir ve hassas verileri korumak icin kullanilmamalidir.</p>', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (226, 32, 'fr', 'Securite et faiblesses', '<p>Votre saisie est traitee localement dans le navigateur. La conversion ASCII n est pas un chiffrement et ne doit pas proteger des donnees sensibles.</p>', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (227, 32, 'de', 'Sicherheit & Schwachstellen', '<p>Ihre Eingabe wird lokal im Browser verarbeitet. ASCII-Konvertierung ist keine Verschluesselung und sollte nicht zum Schutz sensibler Daten verwendet werden.</p>', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (228, 32, 'it', 'Sicurezza e debolezze', '<p>Il tuo input viene elaborato localmente nel browser. La conversione ASCII non e crittografia e non deve essere usata per proteggere dati sensibili.</p>', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (229, 33, 'en', 'How Unicode Encoding Works', '<p>Unicode assigns a unique numeric code to every supported character, symbol, and emoji. For example, the Latin letter A is U+0041, the Cyrillic letter П is U+041F, and 😀 is represented using surrogate pairs in UTF-16. The converter transforms characters into these Unicode representations and back into readable text.</p>', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (230, 33, 'es', 'Como funciona la codificacion Unicode', '<p>Unicode asigna un codigo numerico unico a cada caracter, simbolo y emoji. Por ejemplo, la letra latina A es U+0041, la letra cirilica П es U+041F y 😀 se representa con pares sustitutos en UTF-16. El convertidor transforma caracteres a estas representaciones Unicode y los devuelve a texto legible.</p>', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (231, 33, 'pt', 'Como a codificacao Unicode funciona', '<p>Unicode atribui um codigo numerico unico a cada caractere, simbolo e emoji. Por exemplo, a letra latina A e U+0041, a letra cirilica П e U+041F, e 😀 e representado com pares substitutos em UTF-16. O conversor transforma caracteres nessas representacoes Unicode e retorna para texto legivel.</p>', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (232, 33, 'ru', 'Как работает Unicode-кодирование', '<p>Unicode присваивает уникальный числовой код каждому символу, знаку и эмодзи. Например, латинская буква A — U+0041, кириллическая буква П — U+041F, а 😀 в UTF-16 представляется суррогатной парой. Конвертер преобразует символы в Unicode-представление и обратно в читаемый текст.</p>', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (233, 33, 'tr', 'Unicode Kodlamasi Nasil Calisir', '<p>Unicode, desteklenen her karaktere, simgeye ve emojye benzersiz bir sayisal kod atar. Ornegin Latin harfi A = U+0041, Kiril harfi П = U+041F ve 😀 UTF-16\'da surrogate pair ile temsil edilir. Donusturucu karakterleri bu Unicode gosterimlerine cevirir ve tekrar okunabilir metne donusturur.</p>', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (234, 33, 'fr', 'Comment fonctionne l encodage Unicode', '<p>Unicode attribue un code numerique unique a chaque caractere, symbole et emoji. Par exemple, la lettre latine A est U+0041, la lettre cyrillique П est U+041F, et 😀 est represente avec des paires de substitution en UTF-16. Le convertisseur transforme les caracteres en representations Unicode et les reconvertit en texte lisible.</p>', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (235, 33, 'de', 'Wie Unicode-Codierung funktioniert', '<p>Unicode weist jedem Zeichen, Symbol und Emoji einen eindeutigen numerischen Code zu. Zum Beispiel ist der lateinische Buchstabe A U+0041, der kyrillische Buchstabe П ist U+041F, und 😀 wird in UTF-16 mit Surrogatpaaren dargestellt. Der Konverter wandelt Zeichen in diese Unicode-Darstellungen und zurueck in lesbaren Text um.</p>', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (236, 33, 'it', 'Come funziona la codifica Unicode', '<p>Unicode assegna un codice numerico univoco a ogni carattere, simbolo ed emoji. Per esempio, la lettera latina A e U+0041, la lettera cirillica П e U+041F, e 😀 e rappresentato con coppie surrogate in UTF-16. Il convertitore trasforma i caratteri in queste rappresentazioni Unicode e li riconverte in testo leggibile.</p>', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (237, 34, 'en', 'Security & Weakness', '<p>All conversions happen locally in your browser. Your text is never uploaded or stored on a server.</p>', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (238, 34, 'es', 'Seguridad y debilidades', '<p>Todas las conversiones ocurren localmente en tu navegador. Tu texto no se sube ni se almacena en un servidor.</p>', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (239, 34, 'pt', 'Seguranca e fraquezas', '<p>Todas as conversoes acontecem localmente no seu navegador. Seu texto nao e enviado nem armazenado em servidor.</p>', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (240, 34, 'ru', 'Безопасность и слабые стороны', '<p>Все преобразования выполняются локально в вашем браузере. Ваш текст не загружается на сервер и не сохраняется.</p>', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (241, 34, 'tr', 'Guvenlik ve zayifliklar', '<p>Tum donusumler tarayicinizda yerel olarak gerceklesir. Metniniz sunucuya yuklenmez ve depolanmaz.</p>', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (242, 34, 'fr', 'Securite et faiblesses', '<p>Toutes les conversions se font localement dans votre navigateur. Votre texte n est ni televerse ni stocke sur un serveur.</p>', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (243, 34, 'de', 'Sicherheit & Schwachstellen', '<p>Alle Umwandlungen erfolgen lokal in Ihrem Browser. Ihr Text wird nicht hochgeladen und nicht auf einem Server gespeichert.</p>', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (244, 34, 'it', 'Sicurezza e debolezze', '<p>Tutte le conversioni avvengono localmente nel tuo browser. Il tuo testo non viene caricato o salvato su un server.</p>', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (245, 35, 'en', 'How Caesar Shift Works', '<p>Each letter is shifted by the selected number of positions in the chosen alphabet.</p><p>For example, with shift 3 in the English alphabet: A→D, B→E, X→A.</p><p>Letter case is preserved, while spaces, digits, and punctuation marks stay unchanged.</p>', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (246, 35, 'es', 'Como funciona el desplazamiento Cesar', '<p>Cada letra se desplaza el numero indicado de posiciones en el alfabeto seleccionado.</p><p>Por ejemplo, con desplazamiento 3 en el alfabeto espanol: A→D, Ñ→Q, X→A.</p><p>Se conservan mayusculas y minusculas; espacios, digitos y signos de puntuacion no cambian.</p>', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (247, 35, 'pt', 'Como funciona o deslocamento de Cesar', '<p>Cada letra e deslocada pelo numero indicado de posicoes no alfabeto selecionado.</p><p>Por exemplo, com deslocamento 3 no alfabeto portugues do tool: A→Ã, B→D, X→A.</p><p>Maiusculas e minusculas sao preservadas; espacos, digitos e sinais de pontuacao nao mudam.</p>', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (248, 35, 'ru', 'Как работает сдвиг Цезаря', '<p>Каждая буква сдвигается на указанное количество позиций в выбранном алфавите.</p><p>Например, при сдвиге 3 в русском алфавите: А→Г, Б→Д, Ю→Б.</p><p>Регистр сохраняется, а пробелы, цифры и знаки препинания не изменяются.</p>', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (249, 35, 'tr', 'Sezar kaydirmasi nasil calisir', '<p>Her harf, secilen alfabede belirtilen konum sayisi kadar kaydirilir.</p><p>Ornegin Turkce alfabede 3 kaydirma ile: A→Ç, B→D, Y→B.</p><p>Buyuk/kucuk harf korunur; bosluklar, rakamlar ve noktalama isaretleri degismez.</p>', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (250, 35, 'fr', 'Comment fonctionne le decalage de Cesar', '<p>Chaque lettre est decalee du nombre de positions indique dans l\'alphabet choisi.</p><p>Par exemple, avec un decalage de 3 dans l\'alphabet francais du tool: A→B, B→D, Y→À.</p><p>La casse est conservee; les espaces, chiffres et signes de ponctuation ne changent pas.</p>', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (251, 35, 'de', 'So funktioniert der Caesar-Shift', '<p>Jeder Buchstabe wird um die angegebene Anzahl von Positionen im gewaehlten Alphabet verschoben.</p><p>Zum Beispiel bei Shift 3 im deutschen Alphabet des Tools: A→C, Ä→D, X→A.</p><p>Gross- und Kleinschreibung bleibt erhalten; Leerzeichen, Ziffern und Satzzeichen bleiben unveraendert.</p>', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (252, 35, 'it', 'Come funziona lo shift di Cesare', '<p>Ogni lettera viene spostata del numero indicato di posizioni nell\'alfabeto selezionato.</p><p>Per esempio, con shift 3 nell\'alfabeto italiano: A→D, B→E, X→A.</p><p>Maiuscole e minuscole sono conservate; spazi, cifre e segni di punteggiatura non cambiano.</p>', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (253, 36, 'en', 'Security and Practical Limits', '<p>Caesar cipher is a classical learning example, not a secure encryption method. Its keyspace is limited by the selected alphabet, so it can be brute-forced quickly.</p><p>Use Caesar Cracker for key search and analysis.</p>', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (254, 36, 'es', 'Seguridad y limites practicos', '<p>El cifrado Cesar es un ejemplo educativo clasico, no un metodo seguro. Su espacio de claves esta limitado por el alfabeto seleccionado y se puede probar rapidamente por fuerza bruta.</p><p>Para busqueda de claves y analisis, use Caesar Cracker.</p>', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (255, 36, 'pt', 'Seguranca e limites praticos', '<p>A cifra de Cesar e um exemplo educacional classico, nao um metodo seguro de criptografia. O espaco de chaves e limitado pelo alfabeto selecionado e pode ser testado rapidamente por forca bruta.</p><p>Para busca de chaves e analise, use Caesar Cracker.</p>', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (256, 36, 'ru', 'Стойкость и практические ограничения', '<p>Шифр Цезаря — учебный исторический пример, а не безопасный способ шифрования. Пространство ключей ограничено размером выбранного алфавита, поэтому варианты быстро перебираются.</p><p>Для перебора ключей и анализа используйте Caesar Cracker.</p>', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (257, 36, 'tr', 'Guvenlik ve pratik sinirlar', '<p>Sezar sifresi egitsel ve klasik bir ornektir, guvenli bir sifreleme yontemi degildir. Anahtar uzayi secilen alfabenin boyutuyla sinirlidir ve hizla brute-force edilebilir.</p><p>Anahtar arama ve analiz icin Caesar Cracker\'i kullanin.</p>', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (258, 36, 'fr', 'Securite et limites pratiques', '<p>Le chiffre de Cesar est un exemple historique educatif, pas une methode de protection moderne. Son espace de cles est limite par l\'alphabet choisi et se teste rapidement par force brute.</p><p>Pour la recherche de cles et l\'analyse, utilisez Caesar Cracker.</p>', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (259, 36, 'de', 'Sicherheit und Grenzen', '<p>Die Caesar-Verschluesselung ist ein klassisches Lernbeispiel und keine sichere Verschluesselungsmethode. Der Schluesselraum ist durch das gewaehlte Alphabet begrenzt und laesst sich schnell brute-forcen.</p><p>Fuer Schluesselsuche und Analyse verwenden Sie Caesar Cracker.</p>', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_blocks_translations` (`id`, `block_id`, `language`, `title`, `text`, `created_at`, `updated_at`) VALUES (260, 36, 'it', 'Sicurezza e limiti pratici', '<p>Il cifrario di Cesare e un esempio didattico classico, non un metodo sicuro. Lo spazio delle chiavi e limitato dall\'alfabeto selezionato e puo essere provato rapidamente con brute force.</p><p>Per ricerca delle chiavi e analisi, usa Caesar Cracker.</p>', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
