INSERT INTO `ciphers_faq` (`id`, `app_id`, `sort_order`, `show_in_category`, `published`, `created_at`, `updated_at`) VALUES (90, 11, 60, 1, 1, '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (15, 13, 'en', 'Is Hex encryption?', 'No. Hex is a byte representation format, not an encryption method. It can be converted back to original data.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (16, 13, 'ru', 'Hex — это шифрование?', 'Нет. Hex — это формат представления байтов, а не метод шифрования. Его можно легко преобразовать обратно в исходные данные.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (17, 12, 'en', 'Can I decode hex with spaces?', 'Yes. Spaces, line breaks, and separators can be ignored if the hex sequence itself contains valid character pairs.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (18, 12, 'ru', 'Можно ли декодировать hex с пробелами?', 'Да. Пробелы, переносы строк и разделители можно игнорировать, если сама hex-последовательность содержит корректные пары символов.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (19, 11, 'en', 'Why is a hex string longer than the original text?', 'Because each byte is represented by two hex characters. So text-form hex is usually about twice the length of the original bytes.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (20, 11, 'ru', 'Почему hex-строка длиннее исходного текста?', 'Потому что каждый байт представляется двумя hex-символами. Поэтому размер текстового hex-представления обычно примерно в два раза больше исходных байтов.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (21, 10, 'en', 'Which symbols are valid in hex?', 'Hex uses digits 0-9 and letters A-F. Case is not important: a-f and A-F mean the same.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (22, 10, 'ru', 'Какие символы допустимы в hex?', 'В hex используются цифры 0-9 и буквы A-F. Регистр обычно не важен: a-f и A-F означают одно и то же.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (23, 9, 'en', 'Why can hex decoding fail?', 'Most often because of an odd number of symbols or characters outside the 0-9 and A-F range.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (24, 9, 'ru', 'Почему декодирование hex может не работать?', 'Чаще всего причина в нечетном количестве символов или наличии символов вне диапазона 0-9 и A-F.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (25, 8, 'en', 'Where is Hex used?', 'Hex is used in programming, protocol debugging, binary file analysis, hashes, color codes, URL encoding, and byte representation.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (26, 8, 'ru', 'Где используется Hex?', 'Hex используется в программировании, отладке протоколов, анализе бинарных файлов, хешах, цветовых кодах, URL encoding и представлении байтов.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (27, 20, 'en', 'What is a JWT?', 'JWT (JSON Web Token) is a compact, self-contained token format used for authentication and secure data exchange. It is widely used in OAuth, OpenID Connect, and as a Bearer token in Authorization headers.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (28, 20, 'ru', 'Что такое JWT?', 'JWT (JSON Web Token) — компактный самодостаточный формат токена для аутентификации и безопасного обмена данными. Широко используется в OAuth, OpenID Connect и в Authorization headers как Bearer token.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (29, 19, 'en', 'Does this tool verify JWT signatures?', 'No. This tool only decodes and inspects token structure — header, payload, and claims. Signature verification and token validation are not performed.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (30, 19, 'ru', 'Этот инструмент проверяет подпись JWT?', 'Нет. Инструмент только декодирует и отображает структуру токена — header, payload и claims. Проверка подписи и валидация токена не выполняются.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (31, 18, 'en', 'Is JWT decoding safe?', 'Yes. Decoding simply converts Base64URL data into readable JSON.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (32, 18, 'ru', 'Безопасно ли декодировать JWT?', 'Да. Декодирование только преобразует Base64URL-данные в читаемый JSON.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (33, 17, 'en', 'Can I decode expired tokens?', 'Yes. Expired tokens can still be decoded and inspected — useful for auth debugging and investigating access token issues.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (34, 17, 'ru', 'Можно декодировать просроченные токены?', 'Да. Просроченные токены можно декодировать и анализировать — это полезно при отладке auth-flow и проблем с access token.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (35, 16, 'en', 'Are my tokens uploaded anywhere?', 'No. All decoding happens locally in your browser. Your tokens never leave your device.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (36, 16, 'ru', 'Токены куда-то загружаются?', 'Нет. Все декодирование происходит локально в браузере. Токены никогда не покидают ваше устройство.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (37, 15, 'en', 'Why can anyone decode a JWT?', 'JWT payloads are encoded with Base64URL, not encrypted. They are designed to be readable — confidentiality is provided by transport (HTTPS), not encoding.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (38, 15, 'ru', 'Почему JWT может декодировать любой?', 'JWT payload кодируется в Base64URL, а не шифруется. Он изначально предназначен для чтения — конфиденциальность обеспечивается транспортом (HTTPS), а не кодированием.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (39, 14, 'en', 'What is the signature section?', 'The signature lets the server verify the token was not tampered with. It is computed from the header and payload using a secret key or private key (RS256, HS256, etc.).', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (40, 14, 'ru', 'Что такое секция signature?', 'Signature позволяет серверу проверить, что токен не был изменён. Она вычисляется из header и payload с использованием секретного или приватного ключа (RS256, HS256 и др.).', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (41, 27, 'en', 'What is URL encoding?', 'URL encoding converts unsafe characters into a format that can be transmitted in URLs.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (42, 27, 'ru', 'Что такое URL-кодирование?', 'URL-кодирование преобразует небезопасные символы в формат, который можно безопасно передавать в URL.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (43, 26, 'en', 'Why are spaces replaced with %20?', 'Spaces are not valid in URLs, so they are encoded as %20.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (44, 26, 'ru', 'Почему пробелы заменяются на %20?', 'Пробелы недопустимы в URL, поэтому они кодируются как %20.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (45, 25, 'en', 'When should I use URL encoding?', 'Use it when passing text, search queries, or parameters inside URLs.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (46, 25, 'ru', 'Когда нужно использовать URL-кодирование?', 'Используйте его при передаче текста, поисковых запросов и параметров внутри URL.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (47, 24, 'en', 'Can this tool decode encoded URLs?', 'Yes. Switch to the Decode tab to restore readable text.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (48, 24, 'ru', 'Этот инструмент может декодировать URL?', 'Да. Переключитесь на вкладку Decode, чтобы вернуть текст в читаемый вид.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (49, 23, 'en', 'Is URL encoding secure encryption?', 'No. URL encoding only transforms characters for safe transport.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (50, 23, 'ru', 'URL-кодирование — это шифрование?', 'Нет. URL-кодирование только преобразует символы для безопасной передачи.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (51, 22, 'en', 'Does this tool work offline?', 'Yes. Everything runs directly in your browser.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (52, 22, 'ru', 'Инструмент работает офлайн?', 'Да. Всё работает напрямую в вашем браузере.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (53, 21, 'en', 'Are my inputs sent to a server?', 'No. The tool processes data locally on your device.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (54, 21, 'ru', 'Мои данные отправляются на сервер?', 'Нет. Инструмент обрабатывает данные локально на вашем устройстве.', '2026-05-17 08:36:14', '2026-05-17 08:36:14');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (106, 13, 'tr', 'Hex sifreleme midir?', 'Hayir. Hex sadece baytlarin metinsel gosterimidir.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (107, 13, 'pt', 'Hex e criptografia?', 'Nao. Hex apenas representa bytes.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (108, 13, 'it', 'Hex e crittografia?', 'No. E solo rappresentazione di byte.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (109, 13, 'fr', 'Hex est-il un chiffrement ?', 'Non. Hex est un format de representation.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (110, 13, 'es', 'Hex es cifrado?', 'No. Hex es solo representacion de bytes.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (111, 13, 'de', 'Ist Hex Verschluesselung?', 'Nein. Hex ist nur ein Darstellungsformat fuer Bytes.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (112, 12, 'tr', 'Bosluklu hex cozulebilir mi?', 'Evet. Ciftler gecerliyse ayiricilar yok sayilabilir.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (113, 12, 'pt', 'Posso decodificar hex com espacos?', 'Sim. Separadores podem ser ignorados se os pares forem validos.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (114, 12, 'it', 'Posso decodificare hex con spazi?', 'Si. I separatori possono essere ignorati se le coppie sono valide.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (115, 12, 'fr', 'Peut-on decoder du hex avec espaces ?', 'Oui. Les separateurs peuvent etre ignores si les paires sont valides.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (116, 12, 'es', 'Se puede decodificar hex con espacios?', 'Si. Espacios y separadores se ignoran si los pares hex son validos.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (117, 12, 'de', 'Kann ich Hex mit Leerzeichen dekodieren?', 'Ja. Leerzeichen und Trenner werden ignoriert, wenn die Paare gueltig sind.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (118, 11, 'tr', 'Hex neden daha uzundur?', 'Her bayt iki hex karakteri ile gosterilir.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (119, 11, 'pt', 'Por que hex e mais longo?', 'Cada byte e representado por dois caracteres hex.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (120, 11, 'it', 'Perche la stringa hex e piu lunga?', 'Ogni byte usa due caratteri hex.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (121, 11, 'fr', 'Pourquoi une chaine hex est plus longue ?', 'Chaque byte est represente par deux caracteres hex.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (122, 11, 'es', 'Por que hex es mas largo?', 'Cada byte se representa con dos caracteres hex.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (123, 11, 'de', 'Warum ist Hex laenger?', 'Jedes Byte wird durch zwei Hex-Zeichen dargestellt.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (124, 10, 'tr', 'Hangi karakterler gecerlidir?', '0-9 ve A-F.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (125, 10, 'pt', 'Quais simbolos sao validos?', '0-9 e A-F.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (126, 10, 'it', 'Quali simboli sono validi?', '0-9 e A-F.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (127, 10, 'fr', 'Quels caracteres sont valides ?', '0-9 et A-F.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (128, 10, 'es', 'Que simbolos permite hex?', 'Digitos 0-9 y letras A-F.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (129, 10, 'de', 'Welche Zeichen sind erlaubt?', '0-9 und A-F.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (130, 9, 'tr', 'Cozumleme neden hata verir?', 'Tek sayida karakter veya 0-9/A-F disi semboller.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (131, 9, 'pt', 'Por que a decodificacao pode falhar?', 'Quantidade impar de simbolos ou caracteres fora de 0-9/A-F.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (132, 9, 'it', 'Perche la decodifica puo fallire?', 'Lunghezza dispari o caratteri fuori 0-9/A-F.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (133, 9, 'fr', 'Pourquoi le decodage peut echouer ?', 'Longueur impaire ou caracteres hors 0-9/A-F.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (134, 9, 'es', 'Por que puede fallar la decodificacion?', 'Por longitud impar o caracteres fuera de 0-9 y A-F.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (135, 9, 'de', 'Warum kann Dekodierung fehlschlagen?', 'Bei ungerader Laenge oder ungueltigen Zeichen ausserhalb 0-9/A-F.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (136, 8, 'tr', 'Hex nerede kullanilir?', 'Programlama, protokol hata ayiklama, ikili dosyalar, hash ve renk kodlari.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (137, 8, 'pt', 'Onde Hex e usado?', 'Programacao, depuracao de protocolos, binarios, hashes e cores.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (138, 8, 'it', 'Dove si usa Hex?', 'Programmazione, debug protocolli, file binari, hash e codici colore.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (139, 8, 'fr', 'Ou utilise-t-on Hex ?', 'Programmation, debug de protocoles, binaires, hashes et couleurs.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (140, 8, 'es', 'Donde se usa Hex?', 'En programacion, protocolos, binarios, hashes, colores y representacion de bytes.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (141, 8, 'de', 'Wo wird Hex verwendet?', 'In Programmierung, Protokoll-Debugging, Binaerdateien, Hashes und Farbcodes.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (142, 20, 'tr', 'JWT nedir?', 'JWT (JSON Web Token), kimlik dogrulama ve guvenli veri aktarimi icin kullanilan kompakt, bagimsiz bir token formatidir. OAuth, OpenID Connect ve Authorization header\'larinda Bearer token olarak yaygin bicimde kullanilir.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (143, 20, 'pt', 'O que e JWT?', 'JWT (JSON Web Token) e um formato de token compacto e autossuficiente para autenticacao e troca segura de dados. E amplamente usado em OAuth, OpenID Connect e como Bearer token em cabecalhos Authorization.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (144, 20, 'it', 'Che cos\'e un JWT?', 'JWT (JSON Web Token) e un formato token compatto e autonomo per l\'autenticazione e lo scambio sicuro di dati. E ampiamente usato in OAuth, OpenID Connect e come Bearer token nelle intestazioni Authorization.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (145, 20, 'fr', 'Qu\'est-ce qu\'un JWT ?', 'JWT (JSON Web Token) est un format de token compact et autonome utilise pour l\'authentification et l\'echange securise de donnees. Il est largement utilise dans OAuth, OpenID Connect et comme Bearer token dans les headers Authorization.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (146, 20, 'es', 'Que es un JWT?', 'JWT (JSON Web Token) es un formato compacto y autosuficiente para autenticacion e intercambio seguro de datos. Se usa ampliamente en OAuth, OpenID Connect y como Bearer token en cabeceras Authorization.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (147, 20, 'de', 'Was ist ein JWT?', 'JWT (JSON Web Token) ist ein kompaktes, eigenstaendiges Token-Format fuer Authentifizierung und sicheren Datenaustausch. Es wird in OAuth, OpenID Connect und als Bearer-Token in Authorization-Headern eingesetzt.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (148, 19, 'tr', 'Bu arac JWT imzasini dogrular mi?', 'Hayir. Bu arac yalnizca token yapisini cozumler ve gosterir — header, payload ve claim\'ler. Imza dogrulamasi yapilmaz.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (149, 19, 'pt', 'Esta ferramenta verifica assinaturas JWT?', 'Nao. Esta ferramenta apenas decodifica e inspeciona a estrutura do token — header, payload e claims. A verificacao de assinatura nao e realizada.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (150, 19, 'it', 'Questo strumento verifica le firme JWT?', 'No. Questo strumento decodifica e ispeziona solo la struttura del token — header, payload e claim. La verifica della firma non viene eseguita.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (151, 19, 'fr', 'Cet outil verifie-t-il les signatures JWT ?', 'Non. Cet outil se contente de decoder et d\'inspecter la structure du token — header, payload et claims. La verification de signature et la validation du token ne sont pas effectuees.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (152, 19, 'es', 'Esta herramienta verifica firmas JWT?', 'No. Esta herramienta solo decodifica e inspecciona la estructura del token — header, payload y claims. No se realiza verificacion de firma ni validacion del token.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (153, 19, 'de', 'Prueft dieses Tool JWT-Signaturen?', 'Nein. Dieses Tool dekodiert und zeigt nur die Token-Struktur an — Header, Payload und Claims. Eine Signaturverifizierung wird nicht durchgefuehrt.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (154, 18, 'tr', 'JWT cozumlemek guvenli midir?', 'Evet. Cozumleme yalnizca Base64URL verisini okunur JSON\'a cevirir.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (155, 18, 'pt', 'E seguro decodificar JWT?', 'Sim. Decodificar apenas converte dados Base64URL para JSON legivel.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (156, 18, 'it', 'Decodificare JWT e sicuro?', 'Si. La decodifica converte semplicemente dati Base64URL in JSON leggibile.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (157, 18, 'fr', 'Est-ce sans risque de decoder un JWT ?', 'Oui. Le decodage convertit simplement des donnees Base64URL en JSON lisible.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (158, 18, 'es', 'Es seguro decodificar un JWT?', 'Si. Decodificar solo convierte datos Base64URL a JSON legible.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (159, 18, 'de', 'Ist JWT-Dekodierung sicher?', 'Ja. Beim Dekodieren werden Base64URL-Daten nur in lesbares JSON umgewandelt.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (160, 17, 'tr', 'Suresi dolmus tokenlari cozumleyebilir miyim?', 'Evet. Suresi dolmus tokenlar da cozumlenebilir ve incelenebilir — auth debug ve access token sorunlarini arastirmak icin kullanislidir.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (161, 17, 'pt', 'Posso decodificar tokens expirados?', 'Sim. Tokens expirados ainda podem ser decodificados e inspecionados — util para debug de autenticacao e investigacao de problemas com access tokens.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (162, 17, 'it', 'Posso decodificare token scaduti?', 'Si. Anche i token scaduti possono essere decodificati e ispezionati — utile per il debug di autenticazione e l\'analisi di problemi con access token.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (163, 17, 'fr', 'Puis-je decoder des tokens expires ?', 'Oui. Les tokens expires peuvent toujours etre decodes et inspectes — utile pour le debug d\'authentification et l\'analyse des problemes d\'access token.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (164, 17, 'es', 'Puedo decodificar tokens expirados?', 'Si. Los tokens expirados tambien pueden decodificarse e inspeccionarse — util para auth debugging y el analisis de problemas con access tokens.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (165, 17, 'de', 'Kann ich abgelaufene Token dekodieren?', 'Ja. Auch abgelaufene Token lassen sich dekodieren und analysieren — nuetzlich beim Auth-Debugging und der Untersuchung von Access-Token-Problemen.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (166, 16, 'tr', 'Tokenlarim bir yere yukleniyor mu?', 'Hayir. Tum cozumleme islemi tarayicinizda yerel olarak yapilir. Tokenlariniz hicbir zaman cihazinizdan ayrilmaz.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (167, 16, 'pt', 'Meus tokens sao enviados para algum servidor?', 'Nao. Toda decodificacao acontece localmente no navegador. Seus tokens nunca saem do seu dispositivo.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (168, 16, 'it', 'I miei token vengono caricati da qualche parte?', 'No. Tutta la decodifica avviene localmente nel browser. I tuoi token non lasciano mai il tuo dispositivo.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (169, 16, 'fr', 'Mes tokens sont-ils envoyes quelque part ?', 'Non. Tout le decodage se fait localement dans votre navigateur. Vos tokens ne quittent jamais votre appareil.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (170, 16, 'es', 'Mis tokens se suben a algun servidor?', 'No. Toda la decodificacion ocurre localmente en tu navegador. Tus tokens nunca salen de tu dispositivo.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (171, 16, 'de', 'Werden meine Token irgendwo hochgeladen?', 'Nein. Die gesamte Dekodierung erfolgt lokal in Ihrem Browser. Ihre Token verlassen niemals Ihr Geraet.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (172, 15, 'tr', 'JWT\'yi neden herkes cozumleyebilir?', 'JWT payload Base64URL ile kodlanir, sifrelenmez. Okunabilir olacak sekilde tasarlanmistir — gizlilik, kodlama ile degil, transport (HTTPS) ile saglanir.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (173, 15, 'pt', 'Por que qualquer pessoa pode decodificar JWT?', 'O payload JWT e codificado com Base64URL, nao criptografado. Foi projetado para ser legivel — a confidencialidade e fornecida pelo transporte (HTTPS), nao pela codificacao.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (174, 15, 'it', 'Perche chiunque puo decodificare un JWT?', 'I payload JWT sono codificati con Base64URL, non cifrati. Sono progettati per essere leggibili — la riservatezza e garantita dal trasporto (HTTPS), non dalla codifica.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (175, 15, 'fr', 'Pourquoi tout le monde peut decoder un JWT ?', 'Les payloads JWT sont encodes en Base64URL, pas chiffres. Ils sont concus pour etre lisibles — la confidentialite est assuree par le transport (HTTPS), pas par l\'encodage.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (176, 15, 'es', 'Por que cualquiera puede decodificar un JWT?', 'El payload de JWT esta codificado con Base64URL, no cifrado. Esta disenado para ser legible — la confidencialidad la proporciona el transporte (HTTPS), no la codificacion.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (177, 15, 'de', 'Warum kann jeder ein JWT dekodieren?', 'JWT-Payloads sind mit Base64URL kodiert, nicht verschluesselt. Sie sind absichtlich lesbar — Vertraulichkeit wird durch den Transport (HTTPS) gewaehrleistet, nicht durch die Kodierung.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (178, 14, 'tr', 'Signature bolumu nedir?', 'Signature, tokenin degistirilmedigini sunucunun dogrulamasini saglar. Header ve payload\'dan gizli veya ozel anahtar kullanilarak hesaplanir (RS256, HS256 vb.).', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (179, 14, 'pt', 'O que e a secao signature?', 'A signature permite ao servidor verificar que o token nao foi adulterado. E calculada a partir do header e payload usando uma chave secreta ou privada (RS256, HS256, etc.).', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (180, 14, 'it', 'Cos\'e la sezione signature?', 'La signature consente al server di verificare che il token non sia stato alterato. Viene calcolata da header e payload usando una chiave segreta o privata (RS256, HS256, ecc.).', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (181, 14, 'fr', 'A quoi sert la section signature ?', 'La signature permet au serveur de verifier que le token n\'a pas ete falsifie. Elle est calculee a partir du header et du payload avec une cle secrete ou privee (RS256, HS256, etc.).', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (182, 14, 'es', 'Que es la seccion signature?', 'La signature permite al servidor verificar que el token no fue manipulado. Se calcula a partir del header y payload usando una clave secreta o privada (RS256, HS256, etc.).', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (183, 14, 'de', 'Was ist der Signature-Bereich?', 'Die Signature ermoeglicht dem Server zu pruefen, dass der Token nicht manipuliert wurde. Sie wird aus Header und Payload mit einem geheimen oder privaten Schluessel berechnet (RS256, HS256 usw.).', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (184, 27, 'tr', 'URL kodlama nedir?', 'URL kodlama, guvensiz karakterleri URL\'lerde iletilebilen bir formata donusturur.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (185, 27, 'pt', 'O que e codificacao de URL?', 'A codificacao de URL converte caracteres inseguros em um formato que pode ser transmitido em URLs.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (186, 27, 'it', 'Che cos\'e la codifica URL?', 'La codifica URL converte caratteri non sicuri in un formato trasmissibile negli URL.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (187, 27, 'fr', 'Qu\'est-ce que l\'encodage URL ?', 'L\'encodage URL convertit les caracteres non surs dans un format transmissible en URL.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (188, 27, 'es', 'Que es la codificacion URL?', 'La codificacion URL convierte caracteres no seguros a un formato que puede transmitirse en URLs.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (189, 27, 'de', 'Was ist URL-Kodierung?', 'URL-Kodierung wandelt unsichere Zeichen in ein Format um, das in URLs uebertragen werden kann.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (190, 26, 'tr', 'Bosluklar neden %20 olur?', 'Bosluklar URL\'lerde gecerli degildir, bu nedenle %20 olarak kodlanir.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (191, 26, 'pt', 'Por que espacos viram %20?', 'Espacos nao sao validos em URLs, por isso sao codificados como %20.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (192, 26, 'it', 'Perche gli spazi vengono sostituiti con %20?', 'Gli spazi non sono validi negli URL, quindi vengono codificati come %20.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (193, 26, 'fr', 'Pourquoi les espaces sont-ils remplaces par %20 ?', 'Les espaces ne sont pas valides dans les URLs, donc ils sont encodes en %20.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (194, 26, 'es', 'Por que los espacios se reemplazan con %20?', 'Los espacios no son validos en URLs, por eso se codifican como %20.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (195, 26, 'de', 'Warum werden Leerzeichen durch %20 ersetzt?', 'Leerzeichen sind in URLs nicht gueltig und werden deshalb als %20 kodiert.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (196, 25, 'tr', 'URL kodlamayi ne zaman kullanmaliyim?', 'URL icinde metin, arama sorgusu veya parametre gonderirken kullanin.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (197, 25, 'pt', 'Quando devo usar codificacao de URL?', 'Use ao enviar texto, buscas ou parametros dentro de URLs.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (198, 25, 'it', 'Quando dovrei usare la codifica URL?', 'Quando passi testo, query di ricerca o parametri dentro URL.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (199, 25, 'fr', 'Quand utiliser l\'encodage URL ?', 'Utilisez-le pour transmettre du texte, des recherches ou des parametres dans les URLs.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (200, 25, 'es', 'Cuando debo usar codificacion URL?', 'Usala al pasar texto, consultas de busqueda o parametros dentro de URLs.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (201, 25, 'de', 'Wann sollte ich URL-Kodierung verwenden?', 'Wenn Sie Text, Suchanfragen oder Parameter innerhalb von URLs uebertragen.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (202, 24, 'tr', 'Bu arac kodlu URL\'leri cozer mi?', 'Evet. Okunur metni geri almak icin Decode sekmesine gecin.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (203, 24, 'pt', 'Esta ferramenta consegue decodificar URLs codificadas?', 'Sim. Troque para a aba Decode para recuperar texto legivel.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (204, 24, 'it', 'Questo strumento puo decodificare URL codificati?', 'Si. Passa alla scheda Decode per tornare al testo leggibile.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (205, 24, 'fr', 'Cet outil peut-il decoder des URLs encodees ?', 'Oui. Passez a l\'onglet Decode pour retrouver un texte lisible.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (206, 24, 'es', 'Esta herramienta puede decodificar URLs codificadas?', 'Si. Cambia a la pestaña Decode para recuperar texto legible.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (207, 24, 'de', 'Kann dieses Tool kodierte URLs dekodieren?', 'Ja. Wechseln Sie auf den Decode-Tab, um lesbaren Text wiederherzustellen.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (208, 23, 'tr', 'URL kodlama guvenli sifreleme midir?', 'Hayir. URL kodlama yalnizca karakterleri guvenli tasima icin donusturur.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (209, 23, 'pt', 'Codificacao de URL e criptografia segura?', 'Nao. A codificacao de URL apenas transforma caracteres para transporte seguro.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (210, 23, 'it', 'La codifica URL e una cifratura sicura?', 'No. La codifica URL trasforma solo i caratteri per un trasporto sicuro.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (211, 23, 'fr', 'L\'encodage URL est-il un chiffrement securise ?', 'Non. L\'encodage URL transforme seulement les caracteres pour un transport sur.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (212, 23, 'es', 'La codificacion URL es cifrado seguro?', 'No. La codificacion URL solo transforma caracteres para transporte seguro.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (213, 23, 'de', 'Ist URL-Kodierung sichere Verschluesselung?', 'Nein. URL-Kodierung transformiert Zeichen nur fuer den sicheren Transport.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (214, 22, 'tr', 'Bu arac cevrimdisi calisir mi?', 'Evet. Her sey dogrudan tarayicinizda calisir.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (215, 22, 'pt', 'Esta ferramenta funciona offline?', 'Sim. Tudo roda diretamente no navegador.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (216, 22, 'it', 'Questo strumento funziona offline?', 'Si. Tutto funziona direttamente nel browser.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (217, 22, 'fr', 'Cet outil fonctionne-t-il hors ligne ?', 'Oui. Tout fonctionne directement dans votre navigateur.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (218, 22, 'es', 'Esta herramienta funciona sin conexion?', 'Si. Todo funciona directamente en tu navegador.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (219, 22, 'de', 'Funktioniert das Tool offline?', 'Ja. Alles laeuft direkt in Ihrem Browser.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (220, 21, 'tr', 'Girdilerim sunucuya gonderiliyor mu?', 'Hayir. Arac verileri cihazinizda yerel olarak isler.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (221, 21, 'pt', 'Meus dados sao enviados para um servidor?', 'Nao. A ferramenta processa os dados localmente no seu dispositivo.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (222, 21, 'it', 'I miei dati vengono inviati a un server?', 'No. Lo strumento elabora i dati localmente sul tuo dispositivo.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (223, 21, 'fr', 'Mes donnees sont-elles envoyees a un serveur ?', 'Non. L\'outil traite les donnees localement sur votre appareil.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (224, 21, 'es', 'Mis datos se envian a un servidor?', 'No. La herramienta procesa los datos localmente en tu dispositivo.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (225, 21, 'de', 'Werden meine Eingaben an einen Server gesendet?', 'Nein. Das Tool verarbeitet die Daten lokal auf Ihrem Geraet.', '2026-05-17 08:41:12', '2026-05-17 08:41:12');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (535, 59, 'en', 'Is binary conversion encryption?', 'No. It only changes representation into bits and is reversible.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (536, 59, 'es', 'La conversion binary es cifrado?', 'No. Solo cambia la representacion a bits y es reversible.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (537, 59, 'pt', 'Conversao binary e criptografia?', 'Nao. Ela apenas muda a representacao para bits e e reversivel.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (538, 59, 'ru', 'Binary-преобразование — это шифрование?', 'Нет. Это только способ представления данных в битах, который обратим.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (539, 59, 'tr', 'Binary donusumu sifreleme midir?', 'Hayir. Sadece verinin bitlerle gosterimini degistirir ve geri cevrilebilir.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (540, 59, 'fr', 'La conversion binary est-elle un chiffrement ?', 'Non. Elle change seulement la representation en bits et reste reversible.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (541, 59, 'de', 'Ist Binary-Konvertierung Verschlusselung?', 'Nein. Sie andert nur die Darstellung in Bits und ist reversibel.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (542, 59, 'it', 'La conversione binary e crittografia?', 'No. Cambia solo la rappresentazione in bit ed e reversibile.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (543, 60, 'en', 'Can I decode binary with spaces?', 'Yes. Space-separated 8-bit groups like 01001000 01101001 are supported.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (544, 60, 'es', 'Puedo decodificar binary con espacios?', 'Si. Se admiten grupos de 8 bits separados por espacios, por ejemplo 01001000 01101001.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (545, 60, 'pt', 'Posso decodificar binary com espacos?', 'Sim. Grupos de 8 bits separados por espacos, como 01001000 01101001, sao suportados.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (546, 60, 'ru', 'Можно декодировать binary с пробелами?', 'Да. Поддерживаются группы по 8 бит через пробел, например 01001000 01101001.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (547, 60, 'tr', 'Bosluklu binary veri cozulebilir mi?', 'Evet. 01001000 01101001 gibi boslukla ayrilmis 8 bitlik gruplar desteklenir.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (548, 60, 'fr', 'Puis-je decoder du binary avec des espaces ?', 'Oui. Les groupes de 8 bits separes par des espaces sont pris en charge, par exemple 01001000 01101001.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (549, 60, 'de', 'Kann ich binary mit Leerzeichen dekodieren?', 'Ja. 8-Bit-Gruppen mit Leerzeichen wie 01001000 01101001 werden unterstutzt.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (550, 60, 'it', 'Posso decodificare binary con spazi?', 'Si. Sono supportati gruppi da 8 bit separati da spazi, ad esempio 01001000 01101001.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (551, 61, 'en', 'Why does binary output look longer?', 'Each byte becomes 8 symbols, so binary representation is much longer than plain text.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (552, 61, 'es', 'Por que la salida binary es mas larga?', 'Porque cada byte se representa con 8 simbolos, por eso la representacion binary es mucho mas larga que el texto.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (553, 61, 'pt', 'Por que a saida binary e mais longa?', 'Porque cada byte e representado por 8 simbolos, entao a representacao binary fica muito maior que o texto.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (554, 61, 'ru', 'Почему binary-результат намного длиннее текста?', 'Потому что каждый байт отображается 8 символами, поэтому binary-представление значительно длиннее обычного текста.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (555, 61, 'tr', 'Binary cikti neden daha uzundur?', 'Her bayt 8 sembolle gosterildigi icin binary gosterim duz metinden cok daha uzun olur.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (556, 61, 'fr', 'Pourquoi la sortie binary est-elle plus longue ?', 'Parce que chaque octet est represente par 8 symboles, la representation binary est donc beaucoup plus longue que le texte.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (557, 61, 'de', 'Warum ist die binary-Ausgabe langer?', 'Weil jedes Byte mit 8 Symbolen dargestellt wird, ist die binary-Darstellung deutlich langer als Klartext.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (558, 61, 'it', 'Perche l\'output binary e piu lungo?', 'Perche ogni byte viene rappresentato con 8 simboli, quindi la rappresentazione binary e molto piu lunga del testo.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (559, 62, 'en', 'Which symbols are valid in binary input?', 'Only 0, 1, and separators like spaces between byte groups.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (560, 62, 'es', 'Que simbolos son validos en la entrada binary?', 'Solo 0, 1 y separadores entre grupos de bytes, como espacios.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (561, 62, 'pt', 'Quais simbolos sao validos na entrada binary?', 'Apenas 0, 1 e separadores entre grupos de bytes, como espacos.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (562, 62, 'ru', 'Какие символы допустимы во входном binary?', 'Только 0, 1 и разделители между группами байтов, например пробелы.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (563, 62, 'tr', 'Binary giriste hangi semboller gecerlidir?', 'Sadece 0, 1 ve bayt gruplari arasindaki ayiricilar (or. bosluk) gecerlidir.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (564, 62, 'fr', 'Quels symboles sont valides en entree binary ?', 'Uniquement 0, 1 et des separateurs entre groupes d\'octets, comme les espaces.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (565, 62, 'de', 'Welche Zeichen sind fur binary-Eingaben gultig?', 'Nur 0, 1 und Trenner zwischen Byte-Gruppen, zum Beispiel Leerzeichen.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (566, 62, 'it', 'Quali simboli sono validi nell\'input binary?', 'Solo 0, 1 e separatori tra gruppi di byte, ad esempio spazi.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (567, 63, 'en', 'Why can binary decoding fail?', 'Usually because input contains invalid characters or malformed byte groups.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (568, 63, 'es', 'Por que puede fallar la decodificacion binary?', 'Normalmente por caracteres invalidos o grupos de bytes mal formados.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (569, 63, 'pt', 'Por que a decodificacao binary pode falhar?', 'Normalmente por caracteres invalidos ou grupos de bytes mal formados.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (570, 63, 'ru', 'Почему декодирование binary может завершиться ошибкой?', 'Обычно из-за недопустимых символов или некорректных групп байтов.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (571, 63, 'tr', 'Binary cozumleme neden hata verebilir?', 'Genelde gecersiz karakterler veya hatali bayt gruplari nedeniyle.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (572, 63, 'fr', 'Pourquoi le decodage binary peut-il echouer ?', 'Le plus souvent a cause de caracteres invalides ou de groupes d\'octets mal formes.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (573, 63, 'de', 'Warum kann binary-Dekodierung fehlschlagen?', 'Meist wegen unzulassiger Zeichen oder fehlerhaft gruppierter Bytes.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (574, 63, 'it', 'Perche la decodifica binary puo fallire?', 'Di solito per caratteri non validi o gruppi di byte mal formati.', '2026-05-19 09:53:09', '2026-05-19 09:53:09');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (575, 64, 'en', 'Is Base64 secure?', 'No. It only changes representation and is easily reversible.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (576, 64, 'es', '¿Es seguro Base64?', 'No. Solo cambia la representación y es fácilmente reversible.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (577, 64, 'pt', 'O Base64 é seguro?', 'Não. Apenas muda a representação e é facilmente reversível.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (578, 64, 'ru', 'Base64 безопасен?', 'Нет. Это только способ представления данных, который легко обратить.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (579, 64, 'tr', 'Base64 güvenli mi?', 'Hayır. Yalnızca gösterimi değiştirir ve kolayca geri alınabilir.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (580, 64, 'fr', 'Base64 est-il sécurisé ?', 'Non. Cela ne fait que changer la représentation et est facilement réversible.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (581, 64, 'de', 'Ist Base64 sicher?', 'Nein. Es ändert nur die Darstellung und ist leicht umkehrbar.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (582, 64, 'it', 'Base64 è sicuro?', 'No. Cambia solo la rappresentazione ed è facilmente reversibile.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (583, 65, 'en', 'Why do I see = at the end?', 'It is padding used to align data to 4-character groups.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (584, 65, 'es', '¿Por qué aparece = al final?', 'Es un relleno para alinear los datos en grupos de 4 caracteres.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (585, 65, 'pt', 'Por que aparece = no final?', 'É um preenchimento para alinhar os dados em grupos de 4 caracteres.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (586, 65, 'ru', 'Почему в конце стоит = ?', 'Это padding для выравнивания данных по 4-символьным группам.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (587, 65, 'tr', 'Sonunda neden = var?', 'Verileri 4 karakterlik gruplara hizalamak için kullanılan dolgu karakteridir.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (588, 65, 'fr', 'Pourquoi voit-on = à la fin ?', 'C\'est un rembourrage pour aligner les données en groupes de 4 caractères.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (589, 65, 'de', 'Warum steht am Ende ein = ?', 'Das ist Padding, um Daten auf 4-Zeichen-Gruppen auszurichten.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (590, 65, 'it', 'Perché c\'è un = alla fine?', 'È un padding per allineare i dati a gruppi di 4 caratteri.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (591, 66, 'en', 'Can Base64 be decoded back?', 'Yes. Base64 is easily decoded back to the original data without a password or secret key.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (592, 66, 'es', '¿Se puede decodificar Base64?', 'Sí. Base64 se decodifica fácilmente sin contraseña ni clave secreta.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (593, 66, 'pt', 'É possível decodificar Base64?', 'Sim. Base64 é facilmente decodificado de volta aos dados originais sem senha ou chave secreta.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (594, 66, 'ru', 'Можно ли декодировать Base64 обратно?', 'Да. Base64 легко декодируется обратно в исходные данные без пароля или секретного ключа.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (595, 66, 'tr', 'Base64 geri çözülebilir mi?', 'Evet. Base64, parola veya gizli anahtar olmadan kolayca orijinal veriye geri çözülür.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (596, 66, 'fr', 'Peut-on décoder Base64 en sens inverse ?', 'Oui. Base64 se décode facilement sans mot de passe ni clé secrète.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (597, 66, 'de', 'Kann Base64 zurückdecodiert werden?', 'Ja. Base64 lässt sich ohne Passwort oder Schlüssel einfach zurückdecodieren.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (598, 66, 'it', 'È possibile decodificare Base64?', 'Sì. Base64 può essere facilmente decodificato senza password o chiave segreta.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (599, 67, 'en', 'Where is Base64 used?', 'Base64 is widely used in APIs, email, JSON, JWT, HTTP headers, and when transferring binary data over text-based protocols.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (600, 67, 'es', '¿Dónde se usa Base64?', 'Base64 se usa ampliamente en APIs, email, JSON, JWT, encabezados HTTP y al transmitir datos binarios sobre protocolos de texto.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (601, 67, 'pt', 'Onde é usado o Base64?', 'Base64 é amplamente usado em APIs, email, JSON, JWT, cabeçalhos HTTP e ao transmitir dados binários por protocolos de texto.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (602, 67, 'ru', 'Где используется Base64?', 'Base64 широко используется в API, email, JSON, JWT, HTTP-заголовках и при передаче бинарных данных через текстовые протоколы.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (603, 67, 'tr', 'Base64 nerede kullanılır?', 'Base64, API, e-posta, JSON, JWT, HTTP başlıkları ve metin protokolleri üzerinden ikili veri aktarımında yaygın olarak kullanılır.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (604, 67, 'fr', 'Où est utilisé Base64 ?', 'Base64 est utilisé dans les API, e-mail, JSON, JWT, en-têtes HTTP et pour transmettre des données binaires sur des protocoles texte.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (605, 67, 'de', 'Wo wird Base64 verwendet?', 'Base64 wird in APIs, E-Mail, JSON, JWT, HTTP-Headern und bei der Übertragung von Binärdaten über Textprotokolle eingesetzt.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (606, 67, 'it', 'Dove viene usato Base64?', 'Base64 è ampiamente usato in API, email, JSON, JWT, header HTTP e per trasmettere dati binari su protocolli testuali.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (607, 68, 'en', 'Why is a Base64 string longer than the original?', 'Every 3 bytes of data are encoded into 4 Base64 characters, so the string size increases by about 33%.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (608, 68, 'es', '¿Por qué una cadena Base64 es más larga que el original?', 'Cada 3 bytes se codifican en 4 caracteres Base64, por lo que el tamaño aumenta aproximadamente un 33%.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (609, 68, 'pt', 'Por que uma string Base64 é mais longa que o original?', 'Cada 3 bytes são codificados em 4 caracteres Base64, então o tamanho aumenta cerca de 33%.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (610, 68, 'ru', 'Почему строка Base64 длиннее исходного текста?', 'При кодировании каждые 3 байта данных преобразуются в 4 символа Base64, поэтому размер строки увеличивается примерно на 33%.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (611, 68, 'tr', 'Base64 dizesi neden orijinalden uzundur?', 'Her 3 bayt, 4 Base64 karakterine kodlandığından boyut yaklaşık %33 artar.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (612, 68, 'fr', 'Pourquoi une chaîne Base64 est-elle plus longue que l\'original ?', 'Chaque 3 octets sont encodés en 4 caractères Base64, augmentant la taille d\'environ 33%.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (613, 68, 'de', 'Warum ist eine Base64-Zeichenkette länger als das Original?', 'Je 3 Bytes werden in 4 Base64-Zeichen kodiert, daher wächst die Größe um etwa 33%.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (614, 68, 'it', 'Perché una stringa Base64 è più lunga dell\'originale?', 'Ogni 3 byte vengono codificati in 4 caratteri Base64, quindi la dimensione aumenta di circa il 33%.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (615, 69, 'en', 'How is Base64 different from encryption?', 'Base64 is not designed to protect data. It is an encoding format, not an encryption method.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (616, 69, 'es', '¿En qué se diferencia Base64 del cifrado?', 'Base64 no protege datos. Es un formato de codificación, no un método de cifrado.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (617, 69, 'pt', 'Como Base64 difere da criptografia?', 'Base64 não protege dados. É um formato de codificação, não um método de criptografia.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (618, 69, 'ru', 'Чем Base64 отличается от шифрования?', 'Base64 не предназначен для защиты данных. Это формат кодирования, а не метод шифрования.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (619, 69, 'tr', 'Base64 şifrelemeden nasıl farklıdır?', 'Base64 verileri korumak için tasarlanmamıştır. Bir kodlama biçimidir, şifreleme yöntemi değildir.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (620, 69, 'fr', 'En quoi Base64 diffère-t-il du chiffrement ?', 'Base64 ne protège pas les données. C\'est un format d\'encodage, pas une méthode de chiffrement.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (621, 69, 'de', 'Wie unterscheidet sich Base64 von Verschlüsselung?', 'Base64 schützt keine Daten. Es ist ein Kodierungsformat, kein Verschlüsselungsverfahren.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (622, 69, 'it', 'In cosa differisce Base64 dalla crittografia?', 'Base64 non protegge i dati. È un formato di codifica, non un metodo di crittografia.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (623, 70, 'en', 'Can a password be stored in Base64?', 'No. Base64 does not provide data security, so storing passwords this way is unsafe.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (624, 70, 'es', '¿Se puede guardar una contraseña en Base64?', 'No. Base64 no proporciona seguridad, por lo que almacenar contraseñas así es inseguro.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (625, 70, 'pt', 'É seguro guardar uma senha em Base64?', 'Não. Base64 não fornece segurança, portanto armazenar senhas assim é inseguro.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (626, 70, 'ru', 'Можно ли хранить пароль в Base64?', 'Нет. Base64 не обеспечивает безопасность данных, поэтому хранить пароли в таком виде небезопасно.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (627, 70, 'tr', 'Şifre Base64 ile saklanabilir mi?', 'Hayır. Base64 güvenlik sağlamaz, bu nedenle şifreleri bu şekilde saklamak güvensizdir.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (628, 70, 'fr', 'Peut-on stocker un mot de passe en Base64 ?', 'Non. Base64 ne sécurise pas les données, stocker des mots de passe ainsi est risqué.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (629, 70, 'de', 'Kann ein Passwort in Base64 gespeichert werden?', 'Nein. Base64 bietet keine Datensicherheit, daher ist es unsicher, Passwörter so zu speichern.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (630, 70, 'it', 'Si può salvare una password in Base64?', 'No. Base64 non garantisce sicurezza, quindi salvare password in questo modo è insicuro.', '2026-05-19 09:54:28', '2026-05-19 09:54:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (631, 71, 'en', 'What is an ASCII converter?', 'An ASCII converter transforms regular text into ASCII character codes and can also decode ASCII codes back into readable text.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (632, 71, 'es', 'Que es un convertidor ASCII?', 'Un convertidor ASCII transforma texto normal en codigos ASCII y tambien puede decodificar codigos ASCII de vuelta a texto legible.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (633, 71, 'pt', 'O que e um conversor ASCII?', 'Um conversor ASCII transforma texto comum em codigos ASCII e tambem pode decodificar codigos ASCII de volta para texto legivel.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (634, 71, 'ru', 'Что такое ASCII-конвертер?', 'ASCII-конвертер преобразует обычный текст в ASCII-коды символов и может декодировать ASCII-коды обратно в читаемый текст.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (635, 71, 'tr', 'ASCII donusturucu nedir?', 'ASCII donusturucu normal metni ASCII karakter kodlarina cevirir ve ASCII kodlarini tekrar okunabilir metne cozumleyebilir.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (636, 71, 'fr', 'Qu est-ce qu un convertisseur ASCII ?', 'Un convertisseur ASCII transforme du texte normal en codes ASCII et peut aussi decoder des codes ASCII vers du texte lisible.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (637, 71, 'de', 'Was ist ein ASCII-Konverter?', 'Ein ASCII-Konverter wandelt normalen Text in ASCII-Zeichencodes um und kann ASCII-Codes wieder in lesbaren Text dekodieren.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (638, 71, 'it', 'Che cos e un convertitore ASCII?', 'Un convertitore ASCII trasforma testo normale in codici ASCII e puo anche decodificare codici ASCII in testo leggibile.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (639, 72, 'en', 'Does this tool work offline?', 'Yes. The conversion runs directly in your browser and does not require sending text to a server.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (640, 72, 'es', 'Esta herramienta funciona sin conexion?', 'Si. La conversion se ejecuta directamente en tu navegador y no requiere enviar texto a un servidor.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (641, 72, 'pt', 'Esta ferramenta funciona offline?', 'Sim. A conversao roda diretamente no navegador e nao exige envio de texto para servidor.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (642, 72, 'ru', 'Этот инструмент работает офлайн?', 'Да. Конвертация выполняется прямо в браузере и не требует отправки текста на сервер.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (643, 72, 'tr', 'Bu arac cevrimdisi calisir mi?', 'Evet. Donusum tarayicinizda dogrudan calisir ve metnin sunucuya gonderilmesini gerektirmez.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (644, 72, 'fr', 'Cet outil fonctionne-t-il hors ligne ?', 'Oui. La conversion s execute directement dans votre navigateur sans envoyer le texte a un serveur.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (645, 72, 'de', 'Funktioniert dieses Tool offline?', 'Ja. Die Konvertierung laeuft direkt im Browser und erfordert kein Senden von Text an einen Server.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (646, 72, 'it', 'Questo strumento funziona offline?', 'Si. La conversione avviene direttamente nel browser e non richiede invio del testo a un server.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (647, 73, 'en', 'What ASCII format does the tool use?', 'The default format is decimal ASCII codes separated by spaces.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (648, 73, 'es', 'Que formato ASCII usa la herramienta?', 'El formato por defecto es ASCII decimal con codigos separados por espacios.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (649, 73, 'pt', 'Qual formato ASCII a ferramenta usa?', 'O formato padrao e ASCII decimal com codigos separados por espacos.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (650, 73, 'ru', 'Какой формат ASCII использует инструмент?', 'По умолчанию используются десятичные ASCII-коды, разделенные пробелами.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (651, 73, 'tr', 'Arac hangi ASCII formatini kullaniyor?', 'Varsayilan format boslukla ayrilan onluk ASCII kodlaridir.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (652, 73, 'fr', 'Quel format ASCII utilise l outil ?', 'Le format par defaut est ASCII decimal avec des codes separes par des espaces.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (653, 73, 'de', 'Welches ASCII-Format verwendet das Tool?', 'Standardmaessig werden dezimale ASCII-Codes mit Leerzeichen als Trennzeichen genutzt.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (654, 73, 'it', 'Quale formato ASCII usa lo strumento?', 'Il formato predefinito e ASCII decimale con codici separati da spazi.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (655, 74, 'en', 'Can ASCII encode all characters?', 'No. Standard ASCII supports only 128 characters, mainly English letters, digits, punctuation, and control characters.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (656, 74, 'es', 'ASCII puede codificar todos los caracteres?', 'No. ASCII estandar solo soporta 128 caracteres, principalmente letras inglesas, digitos, puntuacion y caracteres de control.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (657, 74, 'pt', 'ASCII codifica todos os caracteres?', 'Nao. ASCII padrao suporta apenas 128 caracteres, principalmente letras inglesas, digitos, pontuacao e caracteres de controle.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (658, 74, 'ru', 'ASCII может кодировать любые символы?', 'Нет. Стандартный ASCII поддерживает только 128 символов: в основном английские буквы, цифры, знаки пунктуации и управляющие символы.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (659, 74, 'tr', 'ASCII tum karakterleri kodlayabilir mi?', 'Hayir. Standart ASCII yalnizca 128 karakteri destekler; agirlikli olarak Ingilizce harfler, rakamlar, noktalama ve kontrol karakterleri.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (660, 74, 'fr', 'ASCII peut-il encoder tous les caracteres ?', 'Non. L ASCII standard prend en charge seulement 128 caracteres, principalement lettres anglaises, chiffres, ponctuation et caracteres de controle.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (661, 74, 'de', 'Kann ASCII alle Zeichen kodieren?', 'Nein. Standard-ASCII unterstuetzt nur 128 Zeichen, vor allem englische Buchstaben, Ziffern, Satzzeichen und Steuerzeichen.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (662, 74, 'it', 'ASCII puo codificare tutti i caratteri?', 'No. ASCII standard supporta solo 128 caratteri, principalmente lettere inglesi, cifre, punteggiatura e caratteri di controllo.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (663, 75, 'en', 'Is ASCII the same as Unicode?', 'No. ASCII is an older limited character set, while Unicode supports many languages, symbols, and emoji.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (664, 75, 'es', 'ASCII es lo mismo que Unicode?', 'No. ASCII es un conjunto antiguo y limitado, mientras Unicode soporta muchos idiomas, simbolos y emoji.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (665, 75, 'pt', 'ASCII e igual a Unicode?', 'Nao. ASCII e um conjunto antigo e limitado, enquanto Unicode suporta muitos idiomas, simbolos e emoji.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (666, 75, 'ru', 'ASCII — это то же самое, что Unicode?', 'Нет. ASCII — старый ограниченный набор символов, а Unicode поддерживает множество языков, символов и эмодзи.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (667, 75, 'tr', 'ASCII ile Unicode ayni sey mi?', 'Hayir. ASCII eski ve sinirli bir karakter kumesidir, Unicode ise bircok dili, sembolu ve emojiyi destekler.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (668, 75, 'fr', 'ASCII est-il la meme chose que Unicode ?', 'Non. ASCII est un jeu de caracteres ancien et limite, alors que Unicode prend en charge de nombreuses langues, symboles et emoji.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (669, 75, 'de', 'Ist ASCII dasselbe wie Unicode?', 'Nein. ASCII ist ein aelterer, begrenzter Zeichensatz, waehrend Unicode viele Sprachen, Symbole und Emojis unterstuetzt.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (670, 75, 'it', 'ASCII e uguale a Unicode?', 'No. ASCII e un set di caratteri vecchio e limitato, mentre Unicode supporta molte lingue, simboli ed emoji.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (671, 76, 'en', 'Is ASCII encoding secure?', 'No. ASCII is not encryption. It only represents characters as numbers and can be easily reversed.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (672, 76, 'es', 'La codificacion ASCII es segura?', 'No. ASCII no es cifrado. Solo representa caracteres como numeros y se puede revertir facilmente.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (673, 76, 'pt', 'Codificacao ASCII e segura?', 'Nao. ASCII nao e criptografia. Apenas representa caracteres como numeros e pode ser revertido facilmente.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (674, 76, 'ru', 'ASCII-кодирование безопасно?', 'Нет. ASCII — это не шифрование. Это лишь представление символов в виде чисел, которое легко обратить.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (675, 76, 'tr', 'ASCII kodlama guvenli midir?', 'Hayir. ASCII sifreleme degildir. Sadece karakterleri sayilarla gosterir ve kolayca tersine cevrilebilir.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (676, 76, 'fr', 'L encodage ASCII est-il securise ?', 'Non. ASCII n est pas un chiffrement. Il represente simplement les caracteres en nombres et peut etre inverse facilement.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (677, 76, 'de', 'Ist ASCII-Kodierung sicher?', 'Nein. ASCII ist keine Verschluesselung. Es stellt Zeichen nur als Zahlen dar und laesst sich leicht rueckgaengig machen.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (678, 76, 'it', 'La codifica ASCII e sicura?', 'No. ASCII non e crittografia. Rappresenta solo i caratteri come numeri ed e facilmente reversibile.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (679, 77, 'en', 'Why do spaces become 32?', 'In ASCII, every character has a numeric code, and the space character is represented by code 32.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (680, 77, 'es', 'Por que los espacios se convierten en 32?', 'En ASCII, cada caracter tiene un codigo numerico y el espacio se representa con el codigo 32.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (681, 77, 'pt', 'Por que espacos viram 32?', 'No ASCII, cada caractere possui um codigo numerico e o espaco e representado pelo codigo 32.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (682, 77, 'ru', 'Почему пробел превращается в 32?', 'В ASCII у каждого символа есть числовой код, и символ пробела обозначается числом 32.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (683, 77, 'tr', 'Neden bosluk 32 oluyor?', 'ASCII\'de her karakterin bir sayisal kodu vardir ve bosluk karakteri 32 koduyla temsil edilir.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (684, 77, 'fr', 'Pourquoi les espaces deviennent-ils 32 ?', 'En ASCII, chaque caractere a un code numerique et le caractere espace est represente par le code 32.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (685, 77, 'de', 'Warum werden Leerzeichen zu 32?', 'In ASCII hat jedes Zeichen einen Zahlenwert, und das Leerzeichen wird durch den Code 32 dargestellt.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (686, 77, 'it', 'Perche gli spazi diventano 32?', 'In ASCII, ogni carattere ha un codice numerico e il carattere spazio e rappresentato dal codice 32.', '2026-05-19 10:31:22', '2026-05-19 10:31:22');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (687, 78, 'en', 'What is Unicode?', 'Unicode is a universal character encoding standard that supports text from almost all languages and symbol systems.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (688, 78, 'es', 'Que es Unicode?', 'Unicode es un estandar universal de codificacion de caracteres que soporta texto de casi todos los idiomas y sistemas de simbolos.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (689, 78, 'pt', 'O que e Unicode?', 'Unicode e um padrao universal de codificacao de caracteres que suporta texto de quase todos os idiomas e sistemas de simbolos.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (690, 78, 'ru', 'Что такое Unicode?', 'Unicode — это универсальный стандарт кодирования символов, который поддерживает текст почти всех языков и систем символов.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (691, 78, 'tr', 'Unicode nedir?', 'Unicode, neredeyse tum dillerdeki metinleri ve sembol sistemlerini destekleyen evrensel bir karakter kodlama standardidir.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (692, 78, 'fr', 'Qu est-ce que Unicode ?', 'Unicode est un standard universel d encodage de caracteres qui prend en charge le texte de presque toutes les langues et systemes de symboles.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (693, 78, 'de', 'Was ist Unicode?', 'Unicode ist ein universeller Zeichenkodierungsstandard, der Text aus fast allen Sprachen und Symbolsystemen unterstuetzt.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (694, 78, 'it', 'Che cos e Unicode?', 'Unicode e uno standard universale di codifica dei caratteri che supporta testo da quasi tutte le lingue e sistemi di simboli.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (695, 79, 'en', 'What does the Unicode Converter do?', 'It converts regular text into Unicode escape sequences and decodes Unicode sequences back into readable text.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (696, 79, 'es', 'Que hace Unicode Converter?', 'Convierte texto normal en secuencias Unicode escape y decodifica secuencias Unicode de vuelta a texto legible.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (697, 79, 'pt', 'O que o Unicode Converter faz?', 'Ele converte texto comum em sequencias Unicode escape e decodifica sequencias Unicode de volta para texto legivel.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (698, 79, 'ru', 'Что делает Unicode Converter?', 'Он преобразует обычный текст в Unicode escape-последовательности и декодирует Unicode-последовательности обратно в читаемый текст.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (699, 79, 'tr', 'Unicode Converter ne yapar?', 'Normal metni Unicode escape dizilerine donusturur ve Unicode dizilerini tekrar okunabilir metne cozumler.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (700, 79, 'fr', 'Que fait Unicode Converter ?', 'Il convertit du texte normal en sequences Unicode escape et decode les sequences Unicode en texte lisible.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (701, 79, 'de', 'Was macht der Unicode Converter?', 'Er konvertiert normalen Text in Unicode-Escape-Sequenzen und dekodiert Unicode-Sequenzen zurueck in lesbaren Text.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (702, 79, 'it', 'Cosa fa Unicode Converter?', 'Converte testo normale in sequenze Unicode escape e decodifica sequenze Unicode in testo leggibile.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (703, 80, 'en', 'Does this tool support emoji?', 'Yes. Unicode includes emoji, symbols, mathematical characters, and many international scripts.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (704, 80, 'es', 'Esta herramienta soporta emoji?', 'Si. Unicode incluye emoji, simbolos, caracteres matematicos y muchos alfabetos internacionales.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (705, 80, 'pt', 'Esta ferramenta suporta emoji?', 'Sim. Unicode inclui emoji, simbolos, caracteres matematicos e muitos alfabetos internacionais.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (706, 80, 'ru', 'Поддерживает ли инструмент эмодзи?', 'Да. Unicode включает эмодзи, символы, математические знаки и многие международные алфавиты.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (707, 80, 'tr', 'Bu arac emojileri destekler mi?', 'Evet. Unicode; emoji, semboller, matematik karakterleri ve bircok uluslararasi yazi sistemini kapsar.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (708, 80, 'fr', 'Cet outil prend-il en charge les emoji ?', 'Oui. Unicode inclut les emoji, symboles, caracteres mathematiques et de nombreux alphabets internationaux.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (709, 80, 'de', 'Unterstuetzt das Tool Emojis?', 'Ja. Unicode umfasst Emojis, Symbole, mathematische Zeichen und viele internationale Schriftsysteme.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (710, 80, 'it', 'Questo strumento supporta gli emoji?', 'Si. Unicode include emoji, simboli, caratteri matematici e molti alfabeti internazionali.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (711, 81, 'en', 'Is Unicode the same as ASCII?', 'No. ASCII supports only basic English characters, while Unicode supports thousands of characters from many languages.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (712, 81, 'es', 'Unicode es igual que ASCII?', 'No. ASCII solo soporta caracteres basicos en ingles, mientras Unicode soporta miles de caracteres de muchos idiomas.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (713, 81, 'pt', 'Unicode e o mesmo que ASCII?', 'Nao. ASCII suporta apenas caracteres basicos em ingles, enquanto Unicode suporta milhares de caracteres de muitos idiomas.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (714, 81, 'ru', 'Unicode — это то же самое, что ASCII?', 'Нет. ASCII поддерживает только базовые английские символы, а Unicode — тысячи символов разных языков.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (715, 81, 'tr', 'Unicode, ASCII ile ayni sey midir?', 'Hayir. ASCII yalnizca temel Ingilizce karakterleri destekler, Unicode ise bircok dilde binlerce karakteri destekler.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (716, 81, 'fr', 'Unicode est-il identique a ASCII ?', 'Non. ASCII ne prend en charge que des caracteres anglais de base, alors que Unicode en prend en charge des milliers dans de nombreuses langues.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (717, 81, 'de', 'Ist Unicode dasselbe wie ASCII?', 'Nein. ASCII unterstuetzt nur grundlegende englische Zeichen, waehrend Unicode tausende Zeichen vieler Sprachen unterstuetzt.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (718, 81, 'it', 'Unicode e lo stesso di ASCII?', 'No. ASCII supporta solo caratteri inglesi di base, mentre Unicode supporta migliaia di caratteri di molte lingue.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (719, 82, 'en', 'Is my text sent to a server?', 'No. The converter works entirely in your browser and processes data locally.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (720, 82, 'es', 'Mi texto se envia a un servidor?', 'No. El convertidor funciona completamente en tu navegador y procesa los datos localmente.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (721, 82, 'pt', 'Meu texto e enviado para um servidor?', 'Nao. O conversor funciona inteiramente no seu navegador e processa os dados localmente.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (722, 82, 'ru', 'Мой текст отправляется на сервер?', 'Нет. Конвертер работает полностью в браузере и обрабатывает данные локально.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (723, 82, 'tr', 'Metnim sunucuya gonderiliyor mu?', 'Hayir. Donusturucu tamamen tarayicinizda calisir ve veriyi yerel olarak isler.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (724, 82, 'fr', 'Mon texte est-il envoye a un serveur ?', 'Non. Le convertisseur fonctionne entierement dans votre navigateur et traite les donnees localement.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (725, 82, 'de', 'Wird mein Text an einen Server gesendet?', 'Nein. Der Konverter arbeitet vollstaendig im Browser und verarbeitet Daten lokal.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (726, 82, 'it', 'Il mio testo viene inviato a un server?', 'No. Il convertitore funziona interamente nel browser e processa i dati localmente.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (727, 83, 'en', 'Why are some Unicode characters represented by two codes?', 'Characters outside the Basic Multilingual Plane, such as emoji, use surrogate pairs in UTF-16 encoding.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (728, 83, 'es', 'Por que algunos caracteres Unicode se representan con dos codigos?', 'Los caracteres fuera del Basic Multilingual Plane, como los emoji, usan pares sustitutos en codificacion UTF-16.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (729, 83, 'pt', 'Por que alguns caracteres Unicode sao representados por dois codigos?', 'Caracteres fora do Basic Multilingual Plane, como emoji, usam pares substitutos na codificacao UTF-16.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (730, 83, 'ru', 'Почему некоторые Unicode-символы представлены двумя кодами?', 'Символы за пределами Basic Multilingual Plane, например эмодзи, в UTF-16 используют суррогатные пары.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (731, 83, 'tr', 'Neden bazi Unicode karakterleri iki kodla gosteriliyor?', 'Emoji gibi Basic Multilingual Plane disindaki karakterler UTF-16 kodlamasinda surrogate pair kullanir.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (732, 83, 'fr', 'Pourquoi certains caracteres Unicode sont-ils representes par deux codes ?', 'Les caracteres hors du Basic Multilingual Plane, comme les emoji, utilisent des paires de substitution en UTF-16.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (733, 83, 'de', 'Warum werden manche Unicode-Zeichen durch zwei Codes dargestellt?', 'Zeichen ausserhalb der Basic Multilingual Plane, wie Emojis, verwenden in UTF-16 Surrogatpaare.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (734, 83, 'it', 'Perche alcuni caratteri Unicode sono rappresentati da due codici?', 'I caratteri fuori dal Basic Multilingual Plane, come gli emoji, usano coppie surrogate nella codifica UTF-16.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (735, 84, 'en', 'Can I decode JavaScript Unicode strings?', 'Yes. The tool supports common JavaScript-style \\uXXXX Unicode sequences.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (736, 84, 'es', 'Puedo decodificar cadenas Unicode de JavaScript?', 'Si. La herramienta soporta secuencias Unicode estilo JavaScript como \\uXXXX.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (737, 84, 'pt', 'Posso decodificar strings Unicode de JavaScript?', 'Sim. A ferramenta suporta sequencias Unicode no estilo JavaScript, como \\uXXXX.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (738, 84, 'ru', 'Можно декодировать JavaScript Unicode-строки?', 'Да. Инструмент поддерживает распространенный JavaScript-формат Unicode-последовательностей \\uXXXX.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (739, 84, 'tr', 'JavaScript Unicode stringlerini cozumleyebilir miyim?', 'Evet. Arac, JavaScript tarzindaki \\uXXXX Unicode dizilerini destekler.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (740, 84, 'fr', 'Puis-je decoder des chaines Unicode JavaScript ?', 'Oui. L outil prend en charge les sequences Unicode au format JavaScript, comme \\uXXXX.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (741, 84, 'de', 'Kann ich JavaScript-Unicode-Strings dekodieren?', 'Ja. Das Tool unterstuetzt gaengige JavaScript-Unicode-Sequenzen wie \\uXXXX.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (742, 84, 'it', 'Posso decodificare stringhe Unicode JavaScript?', 'Si. Lo strumento supporta comuni sequenze Unicode in stile JavaScript come \\uXXXX.', '2026-05-19 11:04:28', '2026-05-19 11:04:28');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (743, 85, 'en', 'Can I change the shift?', 'Yes. You can choose any valid shift value for the selected alphabet. The tool supports both text encryption and decryption.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (744, 85, 'es', 'Puedo cambiar el desplazamiento?', 'Si. Puede elegir cualquier valor valido de desplazamiento segun el alfabeto seleccionado. La herramienta admite cifrado y descifrado de texto.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (745, 85, 'pt', 'Posso alterar o deslocamento?', 'Sim. Voce pode escolher qualquer valor valido de deslocamento conforme o alfabeto selecionado. A ferramenta suporta tanto cifrar quanto decifrar texto.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (746, 85, 'ru', 'Можно ли изменить сдвиг?', 'Да. Вы можете выбрать любое значение сдвига в зависимости от выбранного алфавита. Инструмент поддерживает как шифрование, так и расшифровку текста.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (747, 85, 'tr', 'Kaydirma degerini degistirebilir miyim?', 'Evet. Secilen alfabeye gore gecerli herhangi bir kaydirma degerini secebilirsiniz. Arac hem metin sifrelemeyi hem de cozmeyi destekler.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (748, 85, 'fr', 'Puis-je changer le decalage?', 'Oui. Vous pouvez choisir toute valeur de decalage valide selon l\'alphabet selectionne. L\'outil prend en charge le chiffrement et le dechiffrement du texte.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (749, 85, 'de', 'Kann ich den Shift aendern?', 'Ja. Sie koennen jeden gueltigen Shift-Wert passend zum ausgewaehlten Alphabet waehlen. Das Tool unterstuetzt sowohl Verschluesselung als auch Entschluesselung.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (750, 85, 'it', 'Posso cambiare lo shift?', 'Si. Puoi scegliere qualsiasi valore di shift valido in base all\'alfabeto selezionato. Lo strumento supporta sia cifratura sia decifratura del testo.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (751, 86, 'en', 'Which alphabets are supported?', 'The mini-app supports several alphabets, including English, Russian, and other languages. Select the required alphabet before encrypting or decrypting.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (752, 86, 'es', 'Que alfabetos se admiten?', 'La mini-app admite varios alfabetos, incluidos ingles, ruso y otros idiomas. Seleccione el alfabeto necesario antes de cifrar o descifrar.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (753, 86, 'pt', 'Quais alfabetos sao suportados?', 'A mini-app suporta varios alfabetos, incluindo ingles, russo e outros idiomas. Selecione o alfabeto necessario antes de cifrar ou decifrar.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (754, 86, 'ru', 'Какие алфавиты поддерживаются?', 'Mini-app поддерживает несколько алфавитов, включая английский, русский и другие языки. Выберите нужный алфавит перед шифрованием или расшифровкой.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (755, 86, 'tr', 'Hangi alfabeler destekleniyor?', 'Mini-app Ingilizce, Rusca ve diger diller dahil olmak uzere birkac alfabeyi destekler. Sifreleme veya cozme isleminden once gerekli alfabeyi secin.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (756, 86, 'fr', 'Quels alphabets sont pris en charge?', 'La mini-app prend en charge plusieurs alphabets, dont l\'anglais, le russe et d\'autres langues. Choisissez l\'alphabet voulu avant de chiffrer ou dechiffrer.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (757, 86, 'de', 'Welche Alphabete werden unterstuetzt?', 'Die Mini-App unterstuetzt mehrere Alphabete, darunter Englisch, Russisch und weitere Sprachen. Waehlen Sie das passende Alphabet vor dem Ver- oder Entschluesseln.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (758, 86, 'it', 'Quali alfabeti sono supportati?', 'La mini-app supporta diversi alfabeti, inclusi inglese, russo e altre lingue. Seleziona l\'alfabeto necessario prima di cifrare o decifrare.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (759, 87, 'en', 'What happens to spaces and punctuation?', 'Spaces, digits, and special characters are not changed. Only letters from the selected alphabet are encrypted.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (760, 87, 'es', 'Que ocurre con los espacios y signos de puntuacion?', 'Los espacios, digitos y caracteres especiales no cambian. Solo se cifran las letras del alfabeto seleccionado.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (761, 87, 'pt', 'O que acontece com espacos e pontuacao?', 'Espacos, digitos e caracteres especiais nao mudam. Apenas as letras do alfabeto selecionado sao cifradas.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (762, 87, 'ru', 'Что происходит с пробелами и знаками препинания?', 'Пробелы, цифры и специальные символы не изменяются. Шифруются только буквы выбранного алфавита.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (763, 87, 'tr', 'Bosluklara ve noktalama isaretlerine ne olur?', 'Bosluklar, rakamlar ve ozel karakterler degismez. Yalnizca secilen alfabedeki harfler sifrelenir.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (764, 87, 'fr', 'Que deviennent les espaces et la ponctuation?', 'Les espaces, chiffres et caracteres speciaux ne sont pas modifies. Seules les lettres de l\'alphabet selectionne sont chiffrees.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (765, 87, 'de', 'Was passiert mit Leerzeichen und Satzzeichen?', 'Leerzeichen, Ziffern und Sonderzeichen werden nicht veraendert. Verschluesselt werden nur Buchstaben des ausgewaehlten Alphabets.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (766, 87, 'it', 'Cosa succede a spazi e punteggiatura?', 'Spazi, cifre e caratteri speciali non vengono modificati. Vengono cifrate solo le lettere dell\'alfabeto selezionato.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (767, 88, 'en', 'How secure is the Caesar cipher?', 'The Caesar cipher is considered cryptographically weak and is suitable only for learning, puzzles, and demonstrating basic encryption principles.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (768, 88, 'es', 'Que tan seguro es el cifrado Cesar?', 'El cifrado Cesar se considera criptograficamente debil y solo sirve para aprendizaje, acertijos y demostraciones de principios basicos de cifrado.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (769, 88, 'pt', 'Quao segura e a cifra de Cesar?', 'A cifra de Cesar e considerada criptograficamente fraca e serve apenas para aprendizado, enigmas e demonstracao de principios basicos de criptografia.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (770, 88, 'ru', 'Насколько безопасен шифр Цезаря?', 'Шифр Цезаря считается криптографически слабым и подходит только для обучения, головоломок и демонстрации базовых принципов шифрования.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (771, 88, 'tr', 'Sezar sifresi ne kadar guvenli?', 'Sezar sifresi kriptografik olarak zayif kabul edilir ve yalnizca egitim, bulmacalar ve temel sifreleme ilkelerini gostermek icin uygundur.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (772, 88, 'fr', 'Le chiffre de Cesar est-il securise?', 'Le chiffre de Cesar est considere comme cryptographiquement faible et convient seulement a l\'apprentissage, aux enigmes et a la demonstration des principes de base du chiffrement.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (773, 88, 'de', 'Wie sicher ist die Caesar-Verschluesselung?', 'Die Caesar-Verschluesselung gilt als kryptografisch schwach und eignet sich nur zum Lernen, fuer Raetsel und zur Demonstration grundlegender Verschluesselungsprinzipien.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (774, 88, 'it', 'Quanto e sicuro il cifrario di Cesare?', 'Il cifrario di Cesare e considerato crittograficamente debole ed e adatto solo per apprendimento, enigmi e dimostrazioni dei principi base della cifratura.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (775, 89, 'en', 'What is Live Mode?', 'Live Mode automatically recalculates the result when you change the text or encryption settings. This lets you see the result instantly without pressing the button.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (776, 89, 'es', 'Que es Live Mode?', 'Live Mode recalcula automaticamente el resultado cuando cambia el texto o los parametros de cifrado. Permite ver el resultado al instante sin pulsar el boton.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (777, 89, 'pt', 'O que e Live Mode?', 'Live Mode recalcula automaticamente o resultado quando voce altera o texto ou os parametros de cifragem. Isso permite ver o resultado instantaneamente, sem pressionar o botao.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (778, 89, 'ru', 'Что такое Live Mode?', 'Live Mode автоматически пересчитывает результат при изменении текста или параметров шифрования. Это позволяет мгновенно видеть результат без нажатия кнопки.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (779, 89, 'tr', 'Live Mode nedir?', 'Live Mode metin veya sifreleme parametreleri degistiginde sonucu otomatik olarak yeniden hesaplar. Boylece dugmeye basmadan sonucu aninda gorebilirsiniz.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (780, 89, 'fr', 'Qu\'est-ce que Live Mode?', 'Live Mode recalcule automatiquement le resultat lorsque vous modifiez le texte ou les parametres de chiffrement. Vous voyez ainsi le resultat instantanement, sans appuyer sur le bouton.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (781, 89, 'de', 'Was ist Live Mode?', 'Live Mode berechnet das Ergebnis automatisch neu, wenn Sie den Text oder die Verschluesselungsparameter aendern. So sehen Sie das Ergebnis sofort, ohne den Button zu druecken.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (782, 89, 'it', 'Che cos\'e Live Mode?', 'Live Mode ricalcola automaticamente il risultato quando cambi il testo o i parametri di cifratura. Cosi puoi vedere subito il risultato senza premere il pulsante.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (783, 90, 'en', 'Can I use this tool to crack a Caesar cipher?', 'No. This mini-app is intended only for encryption and decryption with a known shift. For key search and analysis, use Caesar Cracker.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (784, 90, 'es', 'Puedo usar esta herramienta para romper un cifrado Cesar?', 'No. Esta mini-app esta pensada solo para cifrar y descifrar con un desplazamiento conocido. Para busqueda de claves y analisis, use Caesar Cracker.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (785, 90, 'pt', 'Posso usar esta ferramenta para quebrar uma cifra de Cesar?', 'Nao. Esta mini-app e destinada apenas a cifrar e decifrar com deslocamento conhecido. Para busca de chaves e analise, use Caesar Cracker.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (786, 90, 'ru', 'Можно ли использовать этот инструмент для взлома шифра Цезаря?', 'Нет, этот mini-app предназначен только для шифрования и расшифровки с известным сдвигом. Для перебора ключей и анализа используйте Caesar Cracker.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (787, 90, 'tr', 'Bu araci Sezar sifresini kirmak icin kullanabilir miyim?', 'Hayir. Bu mini-app yalnizca bilinen kaydirma ile sifreleme ve cozme icindir. Anahtar arama ve analiz icin Caesar Cracker\'i kullanin.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (788, 90, 'fr', 'Puis-je utiliser cet outil pour casser un chiffre de Cesar?', 'Non. Cette mini-app sert uniquement au chiffrement et au dechiffrement avec un decalage connu. Pour la recherche de cles et l\'analyse, utilisez Caesar Cracker.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (789, 90, 'de', 'Kann ich dieses Tool zum Knacken einer Caesar-Verschluesselung verwenden?', 'Nein. Diese Mini-App ist nur fuer Verschluesselung und Entschluesselung mit bekanntem Shift gedacht. Fuer Schluesselsuche und Analyse verwenden Sie Caesar Cracker.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_faq_translations` (`id`, `faq_id`, `language`, `question`, `answer`, `created_at`, `updated_at`) VALUES (790, 90, 'it', 'Posso usare questo strumento per violare un cifrario di Cesare?', 'No. Questa mini-app e pensata solo per cifrare e decifrare con uno shift noto. Per ricerca delle chiavi e analisi, usa Caesar Cracker.', '2026-05-20 18:35:19', '2026-05-20 18:35:19');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (1, 1, 'en', 'Base64 Encoder & Decoder', 'Encode and decode Base64 directly in your browser. Supports UTF-8, Unicode, JSON payloads, and API data. Data is processed locally and is not sent to the server.', 'Base64 Encoder & Decoder | Ciphers Online', 'Quickly encode and decode Base64 for API workflows and debugging.', '2026-05-17 08:36:13', '2026-05-17 08:36:13');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (2, 1, 'ru', 'Base64 Кодировщик и Декодировщик Онлайн', 'Кодируйте и декодируйте Base64 прямо в браузере. Поддержка UTF-8, Unicode, JSON payload и API-данных. Данные обрабатываются локально и не отправляются на сервер.', 'Base64 Кодировщик и Декодировщик Онлайн | Ciphers Online', 'Быстро кодировать и декодировать Base64 для API и отладки.', '2026-05-17 08:36:13', '2026-05-17 08:36:13');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (3, 2, 'en', 'Hex Encoder & Decoder Online', 'Convert text to hexadecimal format and decode hex back to plain text directly in your browser. Supports UTF-8, Unicode, spaces, and multiline hex sequences. Data is processed locally and is not sent to the server.', 'Hex Encoder & Decoder Online | Ciphers Online', 'Convert text to hex and decode hex sequences back with UTF-8 support.', '2026-05-17 08:36:13', '2026-05-17 08:36:13');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (4, 2, 'ru', 'Hex Кодировщик и Декодировщик Онлайн', 'Преобразуйте текст в hexadecimal-формат и декодируйте hex обратно в обычный текст прямо в браузере. Поддержка UTF-8, Unicode, пробелов и многострочных hex-последовательностей. Данные обрабатываются локально и не отправляются на сервер.', 'Hex Кодировщик и Декодировщик Онлайн | Ciphers Online', 'Преобразуйте текст в hex и обратно с поддержкой UTF-8 и Unicode.', '2026-05-17 08:36:13', '2026-05-17 08:36:13');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (5, 4, 'en', 'JWT Decoder Online', 'Instantly decode JWT and Bearer tokens in your browser for auth debugging, OAuth flows, and API integration.', 'JWT Decoder Online | Ciphers Online', 'Decode JWT header/payload locally in-browser for authentication debugging.', '2026-05-17 08:36:13', '2026-05-17 08:36:13');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (6, 4, 'ru', 'JWT Декодер Онлайн', 'Мгновенно декодируйте JWT и Bearer tokens прямо в браузере для auth debugging, OAuth и API integration.', 'JWT Декодер Онлайн | Ciphers Online', 'Декодируйте JWT header/payload локально в браузере для отладки аутентификации.', '2026-05-17 08:36:13', '2026-05-17 08:36:13');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (7, 3, 'en', 'URL Encode & Decode Online', 'Encode and decode URLs instantly in your browser. Convert unsafe characters into URL-safe format or restore encoded text back to readable form.', 'URL Encode & Decode Online | Ciphers Online', 'Fast URL Encode/Decode for query strings, APIs, and web development.', '2026-05-17 08:36:13', '2026-05-17 08:36:13');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (8, 3, 'ru', 'URL Кодирование и Декодирование Онлайн', 'Мгновенно кодируйте и декодируйте URL прямо в браузере. Преобразуйте небезопасные символы в URL-безопасный формат или верните закодированный текст в читаемый вид.', 'URL Кодирование и Декодирование Онлайн | Ciphers Online', 'Быстрое URL Encode/Decode для query-параметров, API и веб-разработки.', '2026-05-17 08:36:13', '2026-05-17 08:36:13');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (16, 1, 'tr', 'Base64 Kodlayici ve Kod Cozucu Online', 'Base64 verisini dogrudan tarayicinizda kodlayin ve kodunu cozun. UTF-8, Unicode, JSON payload ve API verilerini destekler. Veriler yerel olarak islenir ve sunucuya gonderilmez.', 'Base64 Kodlayici ve Kod Cozucu Online | Ciphers Online', 'Metni Base64\'e dönüştürür ve Base64\'ü tekrar metne çözer. UTF-8 desteklidir.', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (17, 1, 'pt', 'Codificador e Decodificador Base64 Online', 'Codifique e decodifique Base64 diretamente no navegador. Suporta UTF-8, Unicode, payloads JSON e dados de API. Os dados sao processados localmente e nao sao enviados ao servidor.', 'Codificador e Decodificador Base64 Online | Ciphers Online', 'Converte texto em Base64 e decodifica Base64 de volta para texto. Suporta UTF-8.', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (18, 1, 'it', 'Codificatore e Decodificatore Base64 Online', 'Codifica e decodifica Base64 direttamente nel browser. Supporta UTF-8, Unicode, payload JSON e dati API. I dati sono elaborati localmente e non vengono inviati al server.', 'Codificatore e Decodificatore Base64 Online | Ciphers Online', 'Converte testo in Base64 e decodifica Base64 in testo. Supporta UTF-8.', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (19, 1, 'fr', 'Encodeur et Decodeur Base64 en ligne', 'Encodez et decodez Base64 directement dans votre navigateur. Prise en charge UTF-8, Unicode, payloads JSON et donnees d\'API. Les donnees sont traitees localement et ne sont pas envoyees au serveur.', 'Encodeur et Decodeur Base64 en ligne | Ciphers Online', 'Convertit du texte en Base64 et décode Base64 en texte. Supporte l\'UTF-8.', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (20, 1, 'es', 'Codificador y Decodificador Base64 en línea', 'Codifica y decodifica Base64 directamente en tu navegador. Compatible con UTF-8, Unicode, JSON payloads y datos de API. Los datos se procesan localmente y no se envían al servidor.', 'Codificador y Decodificador Base64 en línea | Ciphers Online', 'Convierte texto a Base64 y decodifica Base64 de vuelta a texto. Compatible con UTF-8.', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (21, 1, 'de', 'Base64 Encoder und Decoder Online', 'Kodieren und dekodieren Sie Base64 direkt im Browser. Unterstuetzt UTF-8, Unicode, JSON-Payloads und API-Daten. Die Daten werden lokal verarbeitet und nicht an den Server gesendet.', 'Base64 Encoder und Decoder Online | Ciphers Online', 'Konvertiert Text in Base64 und dekodiert Base64 zurück in Text. Unterstützt UTF-8.', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (22, 2, 'tr', 'Hex Kodlayici ve Cozucu Online', 'Metni hexadecimal formata cevirin ve hex degerini tarayicida tekrar duz metne cozumleyin. UTF-8, Unicode, bosluk ve cok satirli hex dizileri desteklenir.', 'Hex Kodlayici ve Cozucu Online | Ciphers Online', 'UTF-8 metni hex baytlara cevirir ve gecerli hex dizilerini tekrar metne cozer.', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (23, 2, 'pt', 'Codificador e Decodificador Hex Online', 'Converta texto para hexadecimal e decodifique hex para texto no navegador. Suporta UTF-8, Unicode, espacos e sequencias multiline.', 'Codificador e Decodificador Hex Online | Ciphers Online', 'Converte texto UTF-8 em bytes hex e decodifica sequencias hex validas para texto.', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (24, 2, 'it', 'Codificatore e Decodificatore Hex Online', 'Converti testo in formato esadecimale e decodifica hex in testo direttamente nel browser. Supporta UTF-8, Unicode, spazi e sequenze multilinea.', 'Codificatore e Decodificatore Hex Online | Ciphers Online', 'Converte testo UTF-8 in byte hex e decodifica sequenze hex valide in testo leggibile.', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (25, 2, 'fr', 'Encodeur et Decodeur Hex en ligne', 'Convertissez du texte en hexadecimal et decodez du hex en texte directement dans le navigateur. UTF-8, Unicode, espaces et sequences multiline sont pris en charge.', 'Encodeur et Decodeur Hex en ligne | Ciphers Online', 'Convertit du texte UTF-8 en bytes hex et decode les sequences hex valides.', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (26, 2, 'es', 'Codificador y Decodificador Hex Online', 'Convierte texto a formato hexadecimal y decodifica hex a texto plano directamente en el navegador. Soporta UTF-8, Unicode, espacios y secuencias hex multilinea. Los datos se procesan localmente y no se envian al servidor.', 'Codificador y Decodificador Hex Online | Ciphers Online', 'Convierte texto UTF-8 a bytes hex y decodifica secuencias hex validas a texto legible.', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (27, 2, 'de', 'Hex Encoder & Decoder Online', 'Wandeln Sie Text in Hex um und dekodieren Sie Hex direkt im Browser zurueck in Klartext. UTF-8, Unicode, Leerzeichen und mehrzeilige Hex-Folgen werden unterstuetzt. Daten werden lokal verarbeitet.', 'Hex Encoder & Decoder Online | Ciphers Online', 'Wandelt UTF-8-Text in Hex-Bytes um und dekodiert gueltige Hex-Folgen in lesbaren Text.', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (28, 4, 'tr', 'JWT Cozumleyici Online', 'JWT ve Bearer tokenlarini tarayicinizda aninda cozumleyin; auth debug, OAuth akislari ve API entegrasyonu icin.', 'JWT Cozumleyici Online | Ciphers Online', 'Bu ucretsiz online JWT Decoder araci JSON Web Token\'lari dogrudan tarayicida incelemenizi saglar. Hassas verileri yuklemeden JWT header ve payload cozumleyin; claim, son kullanma, algoritma ve token metadatalarini aninda goruntuleyin.', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (29, 4, 'pt', 'Decodificador JWT Online', 'Decodifique JWT e Bearer tokens instantaneamente no navegador para debug de autenticacao, fluxos OAuth e integracao com API.', 'Decodificador JWT Online | Ciphers Online', 'Este JWT Decoder online gratuito permite inspecionar JSON Web Tokens diretamente no navegador. Decodifique header e payload JWT, visualize claims, expiracao, algoritmos e metadados do token sem enviar informacoes sensiveis.', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (30, 4, 'it', 'Decoder JWT Online', 'Decodifica istantaneamente JWT e Bearer token nel browser per il debug di autenticazione, flussi OAuth e integrazione API.', 'Decoder JWT Online | Ciphers Online', 'Questo JWT Decoder online gratuito consente di ispezionare JSON Web Token direttamente nel browser. Decodifica header e payload JWT, visualizza claim, scadenza, algoritmi e metadati del token senza caricare informazioni sensibili.', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (31, 4, 'fr', 'Decodeur JWT en Ligne', 'Decodez instantanement les JWT et Bearer tokens dans votre navigateur pour le debogage d\'authentification, les flux OAuth et l\'integration API.', 'Decodeur JWT en Ligne | Ciphers Online', 'Ce JWT Decoder gratuit en ligne vous permet d\'inspecter des JSON Web Tokens directement dans le navigateur. Decodez header et payload JWT, consultez claims, expiration, algorithmes et metadonnees du token sans televerser d\'informations sensibles.', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (32, 4, 'es', 'Decodificador JWT Online', 'Decodifica JWT y Bearer tokens al instante en tu navegador para auth debugging, flujos OAuth e integracion con API.', 'Decodificador JWT Online | Ciphers Online', 'Este JWT Decoder online gratuito te permite inspeccionar JSON Web Tokens directamente en el navegador. Decodifica header y payload de JWT, revisa claims, expiracion, algoritmos y metadatos del token sin subir informacion sensible.', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (33, 4, 'de', 'JWT Decoder Online', 'Dekodieren Sie JWT- und Bearer-Tokens sofort im Browser fuer Auth-Debugging, OAuth-Flows und API-Integration.', 'JWT Decoder Online | Ciphers Online', 'Dieser kostenlose Online-JWT-Decoder ermoeglicht es, JSON Web Tokens direkt im Browser zu analysieren. Dekodieren Sie JWT-Header und Payload, pruefen Sie Claims, Ablaufzeit, Algorithmen und Token-Metadaten ohne sensible Informationen hochzuladen.', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (34, 3, 'tr', 'URL Kodlama ve Cozme Online', 'URL metinlerini tarayicinizda aninda kodlayin ve cozumleyin. Guvensiz karakterleri URL-guvenli formata donusturun veya kodlu metni tekrar okunur hale getirin.', 'URL Kodlama ve Cozme Online | Ciphers Online', 'Bu ucretsiz URL Encode / Decode araci, gelistiricilerin URL, query string, API istegi ve web uygulamalarinda metni guvenle tasimasina yardim eder. Ozel karakterleri percent-encoded formata cevirin veya kodlu URL\'leri aninda okunur metne donusturun.', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (35, 3, 'pt', 'Codificador e Decodificador de URL Online', 'Codifique e decodifique URLs instantaneamente no navegador. Converta caracteres inseguros para formato seguro de URL ou restaure texto codificado para forma legivel.', 'Codificador e Decodificador de URL Online | Ciphers Online', 'Esta ferramenta gratuita online de URL Encode / Decode ajuda desenvolvedores a transmitir texto com seguranca em URLs, query strings, requisicoes API e aplicacoes web. Codifique caracteres especiais para formato percent-encoded ou decodifique URLs instantaneamente para texto legivel.', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (36, 3, 'it', 'Codifica e Decodifica URL Online', 'Codifica e decodifica URL istantaneamente nel browser. Converti caratteri non sicuri in formato URL-safe o ripristina testo codificato in forma leggibile.', 'Codifica e Decodifica URL Online | Ciphers Online', 'Questo strumento gratuito online URL Encode / Decode aiuta gli sviluppatori a trasmettere testo in modo sicuro in URL, query string, richieste API e applicazioni web. Codifica caratteri speciali in formato percent-encoded o decodifica subito URL codificati in testo leggibile.', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (37, 3, 'fr', 'Encodeur et Decodeur d\'URL en Ligne', 'Encodez et decodez des URL instantanement dans votre navigateur. Convertissez les caracteres non surs en format URL-safe ou restaurez un texte encode en version lisible.', 'Encodeur et Decodeur d\'URL en Ligne | Ciphers Online', 'Cet outil gratuit URL Encode / Decode aide les developpeurs a transmettre du texte en toute securite dans les URLs, query strings, requetes API et applications web. Encodez les caracteres speciaux en format percent-encoded ou decodez instantanement les URLs en texte lisible.', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (38, 3, 'es', 'Codificar y Decodificar URL Online', 'Codifica y decodifica URLs al instante en tu navegador. Convierte caracteres no seguros a un formato seguro para URL o restaura texto codificado a una forma legible.', 'Codificar y Decodificar URL Online | Ciphers Online', 'Esta herramienta gratuita online de URL Encode / Decode ayuda a los desarrolladores a transmitir texto de forma segura en URLs, parametros de consulta, solicitudes API y aplicaciones web. Codifica caracteres especiales a formato percent-encoded o decodifica URLs al instante a texto legible.', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (39, 3, 'de', 'URL Encoder und Decoder Online', 'Kodieren und dekodieren Sie URLs sofort im Browser. Wandeln Sie unsichere Zeichen in ein URL-sicheres Format um oder stellen Sie kodierten Text wieder lesbar her.', 'URL Encoder und Decoder Online | Ciphers Online', 'Dieses kostenlose Online-Tool fuer URL Encode / Decode hilft Entwicklern, Text sicher in URLs, Query-Strings, API-Anfragen und Webanwendungen zu uebertragen. Kodieren Sie Sonderzeichen in ein percent-encoded Format oder dekodieren Sie URLs sofort wieder in lesbaren Text.', '2026-05-17 08:41:11', '2026-05-17 08:41:11');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (47, 8, 'en', 'Binary Converter Online', 'Convert text to binary bytes and decode binary strings back to plain text directly in your browser. Supports UTF-8 input, space-separated byte groups, and fast local processing.', 'Binary Converter Online | Ciphers Online', 'Convert text to binary and decode binary bytes back with UTF-8 support.', '2026-05-17 18:04:27', '2026-05-17 18:04:27');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (48, 8, 'es', 'Convertidor Binary Online', 'Convierte texto a bytes binary y decodifica cadenas binary de vuelta a texto plano directamente en el navegador. Soporta UTF-8, grupos de bytes separados por espacios y procesamiento local rapido.', 'Convertidor Binary Online | Ciphers Online', 'Convierte texto a binary y decodifica bytes binary con soporte UTF-8.', '2026-05-17 18:04:27', '2026-05-17 19:16:01');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (49, 8, 'pt', 'Conversor Binary Online', 'Converta texto em bytes binary e decodifique cadeias binary de volta para texto simples diretamente no navegador. Suporta UTF-8, grupos de bytes separados por espacos e processamento local rapido.', 'Conversor Binary Online | Ciphers Online', 'Converte texto para binary e decodifica bytes binary com suporte UTF-8.', '2026-05-17 18:04:27', '2026-05-17 19:16:01');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (50, 8, 'ru', 'Binary Конвертер Онлайн', 'Преобразуйте текст в binary-байты и декодируйте binary-строки обратно в обычный текст прямо в браузере. Поддерживаются UTF-8, группы байтов через пробел и быстрая локальная обработка.', 'Binary Конвертер Онлайн | Ciphers Online', 'Преобразование текста в binary и декодирование binary-байтов обратно с поддержкой UTF-8.', '2026-05-17 18:04:27', '2026-05-17 19:16:01');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (51, 8, 'tr', 'Binary Donusturucu Online', 'Metni binary baytlara donusturun ve binary dizelerini tarayicida dogrudan duz metne geri cozumleyin. UTF-8, boslukla ayrilmis bayt gruplari ve hizli yerel isleme desteklenir.', 'Binary Donusturucu Online | Ciphers Online', 'Metni binary formata cevirir ve binary baytlari UTF-8 destegiyle tekrar metne cozer.', '2026-05-17 18:04:27', '2026-05-17 19:16:01');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (52, 8, 'fr', 'Convertisseur Binary en ligne', 'Convertissez du texte en octets binary et decodez des chaines binary en texte clair directement dans le navigateur. Prise en charge de l\'UTF-8, des groupes d\'octets separes par espaces et du traitement local rapide.', 'Convertisseur Binary en ligne | Ciphers Online', 'Convertit du texte en binary et decode des octets binary avec prise en charge UTF-8.', '2026-05-17 18:04:27', '2026-05-17 19:16:01');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (53, 8, 'de', 'Binary Konverter Online', 'Wandeln Sie Text in binary-Bytes um und dekodieren Sie binary-Zeichenfolgen direkt im Browser zuruck in Klartext. Unterstutzt UTF-8, per Leerzeichen getrennte Byte-Gruppen und schnelle lokale Verarbeitung.', 'Binary Konverter Online | Ciphers Online', 'Konvertiert Text in binary und dekodiert binary-Bytes mit UTF-8-Unterstutzung.', '2026-05-17 18:04:27', '2026-05-17 19:16:01');
INSERT INTO `ciphers_translations` (`id`, `app_id`, `language`, `name`, `description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES (54, 8, 'it', 'Convertitore Binary Online', 'Converti testo in byte binary e decodifica stringhe binary in testo normale direttamente nel browser. Supporta UTF-8, gruppi di byte separati da spazi ed elaborazione locale veloce.', 'Convertitore Binary Online | Ciphers Online', 'Converte testo in binary e decodifica byte binary con supporto UTF-8.', '2026-05-17 18:04:27', '2026-05-17 19:16:01');
